  5→export type ExportFormat = 'agent-rules' | 'knowledge-brief' | 'obsidian' | 'notion';
  6→export type ExportScope = 'project' | 'all';
  7→export type ExportDepth = 'essential' | 'standard' | 'comprehensive';
  8→
  9→export const DEPTH_CAPS: Record<ExportDepth, number> = {
 10→  essential: 25,
 11→  standard: 80,
 12→  comprehensive: 200,
 13→};
 14→
 15→// Rough token estimate per insight (title + content + metadata summary).
 16→// Used to enforce the hard 60k input token ceiling within the depth cap.
 17→const AVG_TOKENS_PER_INSIGHT = 300;
 18→const MAX_EXPORT_INPUT_TOKENS = 60000;
 19→
 20→export interface ExportInsightRow {
 21→  id: string;
 22→  type: string;
 23→  title: string;
 24→  content: string;
 25→  summary: string;
 26→  confidence: number;
 27→  project_name: string;
 28→  timestamp: string;
 29→}
