 31→export interface ExportContext {
 32→  scope: ExportScope;
 33→  format: ExportFormat;
 34→  depth: ExportDepth;
 35→  projectName?: string;    // set when scope === 'project'
 36→  sessionCount: number;
 37→  projectCount: number;
 38→  dateRange: { from: string; to: string };
 39→  exportDate: string;      // ISO 8601 date for Obsidian frontmatter
 40→}
 41→
 42→/**
 43→ * Apply depth cap and token budget guard, returning the insights to send to the LLM.
 44→ * Also returns totalInsights (before cap) for metadata.
 45→ */
 46→export function applyDepthCap(
 47→  insights: ExportInsightRow[],
 48→  depth: ExportDepth
 49→): { capped: ExportInsightRow[]; totalInsights: number } {
 50→  const totalInsights = insights.length;
 51→  const depthCap = DEPTH_CAPS[depth];
 52→
 53→  // Apply depth cap first
 54→  let capped = insights.slice(0, depthCap);
 55→
 56→  // Token budget guard within the depth cap — safety net for unusually large insights
 57→  let tokenEstimate = 0;
 58→  const tokenBudgeted: ExportInsightRow[] = [];
 59→  for (const insight of capped) {
 60→    tokenEstimate += AVG_TOKENS_PER_INSIGHT;
 61→    if (tokenEstimate > MAX_EXPORT_INPUT_TOKENS) break;
 62→    tokenBudgeted.push(insight);
 63→  }
 64→  capped = tokenBudgeted;
 65→
 66→  return { capped, totalInsights };
 67→}
 68→
 69→/**
 70→ * Format insights for LLM input, grouped by type.
 71→ * Includes project_name on each insight for scope-awareness.
 72→ */
 73→export function buildInsightContext(insights: ExportInsightRow[]): string {
 74→  const grouped: Record<string, ExportInsightRow[]> = {};
 75→  for (const insight of insights) {
 76→    const key = insight.type;
 77→    if (!grouped[key]) grouped[key] = [];
 78→    grouped[key].push(insight);
 79→  }
 80→
 81→  const sections: string[] = [];
 82→
 83→  const typeOrder = ['decision', 'learning', 'technique', 'prompt_quality', 'summary'];
 84→  const typeLabels: Record<string, string> = {
 85→    decision: 'DECISIONS',
 86→    learning: 'LEARNINGS',
 87→    technique: 'TECHNIQUES',
 88→    prompt_quality: 'PROMPT QUALITY',
 89→    summary: 'SESSION SUMMARIES',
 90→  };
 91→
 92→  for (const type of typeOrder) {
 93→    const items = grouped[type];
 94→    if (!items || items.length === 0) continue;
 95→
 96→    const label = typeLabels[type] ?? type.toUpperCase();
 97→    sections.push(`## ${label}\n`);
 98→
 99→    for (const item of items) {
100→      const projectTag = item.project_name ? ` [${item.project_name}]` : '';
101→      const confidence = Math.round(item.confidence * 100);
102→      sections.push(
103→        `### ${item.title}${projectTag} (confidence: ${confidence}%)\n${item.content || item.summary}\n`
104→      );
105→    }
106→  }
107→
108→  return sections.join('\n');
109→}
