 51→  usage?: {
 52→    inputTokens: number;
 53→    outputTokens: number;
 54→  };
 55→}
 56→
 57→// Re-export ParseError so routes can import it from analysis.ts
 58→export type { ParseError };
 59→
 60→// Shape of a saved insight row (matches the SQLite schema)
 61→export interface InsightRow {
 62→  id: string;
 63→  session_id: string;
 64→  project_id: string;
 65→  project_name: string;
 66→  type: string;
 67→  title: string;
