235→ * Analyze prompt quality for a session.
236→ */
237→export async function analyzePromptQuality(
238→  session: SessionData,
239→  messages: SQLiteMessageRow[],
240→  options?: AnalysisOptions
241→): Promise<AnalysisResult> {
242→  if (!isLLMConfigured()) {
243→    return {
244→      success: false,
245→      insights: [],
246→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
247→    };
248→  }
249→
250→  if (messages.length === 0) {
251→    return {
252→      success: false,
253→      insights: [],
254→      error: 'No messages found for this session.',
255→    };
256→  }
257→
258→  const userMessages = messages.filter(m => m.type === 'user');
259→  if (userMessages.length < 2) {
260→    return {
261→      success: false,
262→      insights: [],
263→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
264→    };
265→  }
266→
267→  try {
268→    const client = createLLMClient();
269→    const formattedMessages = formatMessagesForAnalysis(messages);
270→
271→    let analysisInput = formattedMessages;
272→    const estimatedTokens = client.estimateTokens(formattedMessages);
273→    if (estimatedTokens > MAX_INPUT_TOKENS) {
274→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
275→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
276→    }
277→
278→    const prompt = generatePromptQualityPrompt(
279→      session.project_name,
280→      analysisInput,
281→      messages.length
282→    );
283→
284→    options?.onProgress?.({ phase: 'analyzing' });
285→    const response = await client.chat([
286→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
287→      { role: 'user', content: prompt },
288→    ], { signal: options?.signal });
289→
290→    const parsed = parsePromptQualityResponse(response.content);
291→    if (!parsed.success) {
292→      return {
293→        success: false,
294→        insights: [],
295→        error: 'Failed to parse prompt quality analysis. Please try again.',
296→        error_type: parsed.error.error_type,
297→        response_length: parsed.error.response_length,
298→        response_preview: parsed.error.response_preview,
299→      };
300→    }
301→
302→    options?.onProgress?.({ phase: 'saving' });
303→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
304→
305→    // Save new insight, then delete old prompt_quality insights
306→    saveInsightsToDb([insight]);
307→    deleteSessionInsights(session.id, {
308→      includeOnlyTypes: ['prompt_quality'],
309→      excludeIds: [insight.id],
310→    });
311→
312→    return {
313→      success: true,
314→      insights: [insight],
315→      usage: response.usage ? {
316→        inputTokens: response.usage.inputTokens,
317→        outputTokens: response.usage.outputTokens,
318→      } : undefined,
319→    };
320→  } catch (error) {
321→    if (error instanceof Error && error.name === 'AbortError') {
322→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
323→    }
324→    return {
325→      success: false,
326→      insights: [],
327→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
328→      error_type: 'api_error',
329→    };
330→  }
331→}
