698→/**
699→ * Write insight rows to SQLite using prepared statements.
700→ */
701→function saveInsightsToDb(insights: InsightRow[]): void {
702→  const db = getDb();
703→  const insert = db.prepare(`
704→    INSERT OR REPLACE INTO insights (
705→      id, session_id, project_id, project_name, type, title, content,
706→      summary, bullets, confidence, source, metadata, timestamp,
707→      created_at, scope, analysis_version
708→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
709→  `);
710→
711→  const insertMany = db.transaction((rows: InsightRow[]) => {
712→    for (const row of rows) {
713→      insert.run(
714→        row.id,
715→        row.session_id,
716→        row.project_id,
717→        row.project_name,
718→        row.type,
719→        row.title,
720→        row.content,
721→        row.summary,
722→        row.bullets,
723→        row.confidence,
724→        row.source,
725→        row.metadata,
726→        row.timestamp,
727→        row.created_at,
728→        row.scope,
729→        row.analysis_version,
730→      );
731→    }
732→  });
733→
734→  insertMany(insights);
735→}
