737→interface DeleteOptions {
738→  excludeTypes?: string[];
739→  includeOnlyTypes?: string[];
740→  excludeIds?: string[];
741→}
742→
743→/**
744→ * Delete insights for a session, with optional type and ID exclusions.
745→ */
746→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
747→  const db = getDb();
748→  const conditions: string[] = ['session_id = ?'];
749→  const params: (string | number)[] = [sessionId];
750→
751→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
752→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
753→    params.push(...opts.excludeTypes);
754→  }
755→
756→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
757→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
758→    params.push(...opts.includeOnlyTypes);
759→  }
760→
761→  if (opts.excludeIds && opts.excludeIds.length > 0) {
762→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
763→    params.push(...opts.excludeIds);
764→  }
765→
766→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
767→}
