502→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
503→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
504→  parsed.overallAssessment = parsed.overallAssessment || '';
505→  parsed.wastedTurns = parsed.wastedTurns || [];
506→  parsed.antiPatterns = parsed.antiPatterns || [];
507→  parsed.sessionTraits = parsed.sessionTraits || [];
