271→export function buildExportUserPrompt(ctx: ExportContext, insightContext: string): string {
272→  const scopeDescription = ctx.scope === 'project'
273→    ? `Project: ${ctx.projectName}`
274→    : `All projects (${ctx.projectCount} project${ctx.projectCount !== 1 ? 's' : ''})`;
275→
276→  const header = [
277→    `Source: ${scopeDescription}`,
278→    `Sessions analyzed: ${ctx.sessionCount}`,
279→    `Date range: ${ctx.dateRange.from} to ${ctx.dateRange.to}`,
280→  ].join('\n');
281→
282→  return `${header}\n\n${insightContext}`;
