  1→import { Hono } from 'hono';
  2→import { getDb } from '@code-insights/cli/db/client';
  3→import { randomUUID } from 'crypto';
  4→import { parseIntParam } from '../utils.js';
  5→
  6→const app = new Hono();
  7→
  8→const VALID_TYPES = ['summary', 'decision', 'learning', 'technique', 'prompt_quality'] as const;
  9→
 10→app.get('/', (c) => {
 11→  const db = getDb();
 12→  const { projectId, sessionId, type, limit, offset } = c.req.query();
 13→
 14→  const conditions: string[] = [];
 15→  const params: (string | number)[] = [];
 16→
 17→  if (projectId) {
 18→    conditions.push('project_id = ?');
 19→    params.push(projectId);
 20→  }
 21→  if (sessionId) {
 22→    conditions.push('session_id = ?');
 23→    params.push(sessionId);
 24→  }
 25→  if (type) {
 26→    conditions.push('type = ?');
 27→    params.push(type);
 28→  }
 29→
 30→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
 31→  const insights = db.prepare(`
 32→    SELECT id, session_id, project_id, project_name, type, title, content,
 33→           summary, bullets, confidence, source, metadata, timestamp,
 34→           created_at, scope, analysis_version, linked_insight_ids
 35→    FROM insights
 36→    ${where}
 37→    ORDER BY timestamp DESC
 38→    LIMIT ? OFFSET ?
 39→  `).all(...params, parseIntParam(limit, 100), parseIntParam(offset, 0));
 40→
 41→  return c.json({ insights });
 42→});
 43→
 44→app.post('/', async (c) => {
 45→  const db = getDb();
 46→  const body = await c.req.json<{
 47→    sessionId: string;
 48→    projectId: string;
 49→    projectName?: string;   // optional — defaults to ''
 50→    type: string;
 51→    title: string;
 52→    content: string;
 53→    summary?: string;       // optional — defaults to ''
 54→    bullets?: string[];
 55→    confidence?: number;    // optional — defaults to 0
 56→    metadata?: Record<string, unknown>;
 57→  }>();
 58→
 59→  // Validate required string fields
 60→  const required = ['sessionId', 'projectId', 'type', 'title', 'content'] as const;
 61→  for (const field of required) {
 62→    if (!body[field] || typeof body[field] !== 'string') {
 63→      return c.json({ error: `Missing or invalid field: ${field}` }, 400);
 64→    }
 65→  }
 66→
 67→  // Validate type is one of the known insight types
 68→  if (!VALID_TYPES.includes(body.type as typeof VALID_TYPES[number])) {
 69→    return c.json({ error: `type must be one of: ${VALID_TYPES.join(', ')}` }, 400);
 70→  }
 71→
 72→  // Validate confidence is a finite number if provided
 73→  if (body.confidence !== undefined && (typeof body.confidence !== 'number' || !Number.isFinite(body.confidence))) {
 74→    return c.json({ error: 'confidence must be a finite number' }, 400);
 75→  }
 76→
 77→  const id = randomUUID();
 78→  const now = new Date().toISOString();
 79→
 80→  try {
 81→    db.prepare(`
 82→      INSERT INTO insights (
 83→        id, session_id, project_id, project_name, type, title, content,
 84→        summary, bullets, confidence, source, metadata, timestamp, created_at
 85→      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'llm', ?, ?, ?)
 86→    `).run(
 87→      id,
 88→      body.sessionId,
 89→      body.projectId,
 90→      body.projectName ?? '',
 91→      body.type,
 92→      body.title,
 93→      body.content,
 94→      body.summary ?? '',
 95→      body.bullets ? JSON.stringify(body.bullets) : null,
 96→      body.confidence ?? 0,
 97→      body.metadata ? JSON.stringify(body.metadata) : null,
 98→      now,
 99→      now,
100→    );
101→  } catch (err) {
102→    if (err instanceof Error && err.message.includes('FOREIGN KEY constraint failed')) {
103→      return c.json({ error: 'Invalid sessionId or projectId' }, 400);
104→    }
105→    throw err;
106→  }
107→
108→  return c.json({ id }, 201);
109→});
