299→        type: 'prompt-quality',
300→        llm_provider: llmConfig?.provider,
301→        llm_model: llmConfig?.model,
302→        duration_ms: Date.now() - pqStreamStart,
303→        success: result.success,
304→      };
305→      if (!result.success) {
306→        const pqStreamErrorProperties = {
307→          ...pqStreamBaseProperties,
308→          error_type: result.error_type,
309→          error_message: result.error,
310→          response_preview: result.response_preview,
311→        };
312→        trackEvent('analysis_run', pqStreamErrorProperties);
313→        captureError(new Error(result.error ?? 'prompt_quality stream failed'), pqStreamErrorProperties);
314→        await stream.writeSSE({
315→          event: 'error',
316→          data: JSON.stringify({ error: result.error ?? 'Prompt quality analysis failed' }),
317→        });
318→      } else {
319→        trackEvent('analysis_run', pqStreamBaseProperties);
320→        trackEvent('insight_generated', {
321→          type: 'prompt_quality',
322→          count: result.insights.length,
323→        });
324→        await stream.writeSSE({
325→          event: 'complete',
326→          data: JSON.stringify({
327→            success: true,
328→            insightCount: result.insights.length,
329→            tokenUsage: result.usage,
330→            suggestedTitle: null,
331→          }),
332→        });
333→      }
334→    } catch (err) {
335→      const message = err instanceof Error ? err.message : 'Unknown error';
336→      captureError(err, { type: 'prompt_quality_stream', llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
337→      await stream.writeSSE({
338→        event: 'error',
339→        data: JSON.stringify({ error: message }),
340→      }).catch(() => {});
341→    }
342→  });
343→});
