 1→import { Command } from 'commander';
 2→import type { Period, StatsFlags } from './data/types.js';
 3→import { InvalidPeriodError } from './data/types.js';
 4→
 5→const VALID_PERIODS = ['7d', '30d', '90d', 'all'];
 6→
 7→export type { StatsFlags };
 8→
 9→export function applySharedFlags(cmd: Command): Command {
10→  return cmd
11→    .option('-p, --period <period>', 'Time range: 7d, 30d, 90d, all', '7d')
12→    .option('--project <name>', 'Scope to a single project')
13→    .option('--source <tool>', 'Filter by source tool (claude-code, cursor, etc.)')
14→    .option('--no-sync', 'Skip auto-sync before displaying stats');
15→}
16→
17→export function parseFlags(options: Record<string, unknown>): StatsFlags {
18→  const period = (options.period as string) || '7d';
19→  if (!VALID_PERIODS.includes(period)) {
20→    throw new InvalidPeriodError(`Invalid period "${period}". Expected: ${VALID_PERIODS.join(', ')}`);
21→  }
22→  return {
23→    period: period as Period,
24→    project: options.project as string | undefined,
25→    source: options.source as string | undefined,
26→    noSync: !options.sync,  // Commander's --no-sync sets sync=false
27→  };
28→}
