70→          <Route path="/analytics" element={<AnalyticsPage />} />
71→          <Route path="/settings" element={<SettingsPage />} />
72→          <Route path="/export" element={<ExportPage />} />
73→          <Route path="/journal" element={<JournalPage />} />
74→          <Route path="*" element={<Navigate to="/dashboard" replace />} />
75→        </Route>
76→      </Routes>
77→    </BrowserRouter>
78→  );
79→}
