105→        key = insight.project_name;
106→      } else if (view === 'session') {
107→        key = insight.session_id;
108→      } else {
109→        key = getDateGroup(insight.created_at);
110→      }
111→      const arr = groups.get(key) || [];
112→      arr.push(insight);
113→      groups.set(key, arr);
114→    }
115→
116→    const entries = [...groups.entries()];
117→
118→    if (view === 'timeline') {
119→      const sorted = sortDateGroups(entries);
120→      return sorted.map(([key, items]) => ({
121→        key,
122→        label: key,
123→        count: items.length,
124→        insights: items,
125→      }));
126→    }
127→
128→    if (view === 'type') {
129→      return entries.map(([key, items]) => ({
130→        key,
131→        label: INSIGHT_TYPE_LABELS[key as InsightType] || key,
132→        count: items.length,
133→        insights: items,
134→      }));
135→    }
136→
137→    if (view === 'project') {
138→      entries.sort((a, b) => b[1].length - a[1].length);
139→      return entries.map(([key, items]) => ({
140→        key,
141→        label: key,
142→        count: items.length,
143→        insights: items,
144→      }));
145→    }
146→
147→    // session view
148→    entries.sort((a, b) => {
149→      const aTime = Math.max(...a[1].map((i) => new Date(i.created_at).getTime()));
