```typescript
// Line 120+
app.get('/patterns', (c) => {
  const db = getDb();
  const { projectId, limit } = c.req.query();
  const limitNum = parseIntParam(limit, 100);

  const conditions: string[] = ['linked_insight_ids IS NOT NULL'];
  const params: (string | number)[] = [];

  if (projectId) {
    conditions.push('project_id = ?');
    params.push(projectId);
  }

  const where = `WHERE ${conditions.join(' AND ')}`;

  // Fetch insights with links
  const insights = db.prepare(`
    SELECT id, type, title, content, summary, confidence, project_name, 
           timestamp, linked_insight_ids
    FROM insights
    ${where}
    ORDER BY confidence DESC, timestamp DESC
    LIMIT ?
  `).all(...params, limitNum) as Array<{
    id: string;
    type: string;
    title: string;
    content: string;
    summary: string;
    confidence: number;
    project_name: string;
    timestamp: string;
    linked_insight_ids: string;
  }>;

  // Group by linked_insight_ids to form patterns
  const grouped = new Map<string, typeof insights>();
  for (const insight of insights) {
    const linkedIds = insight.linked_insight_ids ? 
      JSON.parse(insight.linked_insight_ids) : [];
    const key = insight.id; // Each insight is in its own group

    if (!grouped.has(key)) grouped.set(key, []);
    grouped.get(key)!.push(insight);
  }

  const patterns = Array.from(grouped.values())
    .filter(group => group.length >= 2)
    .map(group => {
      const theme = generateTheme(group); // Helper
      return {
        theme,
        insightIds: group.map(i => i.id),
        insights: group,
        occurrenceCount: group.length,
        projectCount: new Set(group.map(i => i.project_name)).size,
        confidence: group.reduce((sum, i) => sum + i.confidence, 0) / group.length,
      };
    });

  return c.json({ patterns, totalPatterns: patterns.length });
});
```

