export async function fetchPatterns(params?: { projectId?: string }): Promise<PatternResponse> {
  const url = new URL('/api/insights/patterns', BASE_URL);
  if (params?.projectId) url.searchParams.set('projectId', params.projectId);
  const res = await fetch(url);
  if (!res.ok) throw new Error('Failed to fetch patterns');
  return res.json();
}

export async function analyzePatterns(projectId?: string): Promise<AnalysisResponse> {
  const res = await fetch('/api/analysis/patterns', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ projectId }),
  });
  if (!res.ok) throw new Error('Failed to analyze patterns');
  return res.json();
}
