 91→2. **Decisions**: Technical choices made — with full situation context, reasoning, rejected alternatives, trade-offs, and conditions for revisiting (max 3)
 92→3. **Learnings**: Technical discoveries, gotchas, debugging breakthroughs — with the observable symptom, root cause, and a transferable takeaway (max 5)
 93→4. **Session Character**: Classify the session into exactly one of these types based on its overall nature:
 94→   - deep_focus: Long, concentrated work on a specific problem or area (50+ messages, deep into one topic)
 95→   - bug_hunt: Debugging-driven — investigating errors, tracing issues, fixing bugs
 96→   - feature_build: Building new functionality — creating files, adding endpoints, wiring components
 97→   - exploration: Research-oriented — reading code, searching, understanding before acting
 98→   - refactor: Restructuring existing code — renaming, moving, reorganizing without new features
 99→   - learning: Knowledge-seeking — asking questions, understanding concepts, getting explanations
100→   - quick_task: Short and focused — small fix, config change, or one-off task (<10 messages)
101→
102→Quality Standards:
103→- Only include insights you would write in a team knowledge base for future reference
104→- Each insight MUST reference concrete details: specific file names, library names, error messages, API endpoints, or code patterns
105→- Do not invent file names, APIs, errors, or details not present in the conversation
106→- Rate your confidence in each insight's value (0-100). Only include insights you rate 70+.
107→- It is better to return 0 insights in a category than to include generic or trivial ones
108→- If a session is straightforward with no notable decisions or learnings, say so in the summary and leave other categories empty
109→
110→Length Guidance:
111→- Fill every field in the schema. An empty "trade_offs" or "revisit_when" is worse than a longer response.
112→- Total response: stay under 2000 tokens. If you must cut, drop lower-confidence insights rather than compressing high-confidence ones.
113→- Evidence: 1-3 short quotes per insight, referencing turn labels.
114→- Prefer precision over brevity — a specific 3-sentence insight beats a vague 1-sentence insight.
115→
116→DO NOT include insights like these (too generic/trivial):
117→- "Used debugging techniques to fix an issue"
118→- "Made architectural decisions about the codebase"
119→- "Implemented a new feature" (the summary already covers this)
120→- "Used React hooks for state management" (too generic without specifics)
121→- "Fixed a bug in the code" (what bug? what was the root cause?)
122→- Anything that restates the task without adding transferable knowledge
123→
124→Here are examples of EXCELLENT insights — this is the quality bar:
125→
126→EXCELLENT decision:
127→{
128→  "title": "Use better-sqlite3 instead of sql.js for local database",
129→  "situation": "Needed a SQLite driver for a Node.js CLI that stores session data locally. Single-user, read-heavy from dashboard, occasional writes during sync.",
130→  "choice": "better-sqlite3 — synchronous C++ binding with native SQLite access, no async overhead.",
131→  "reasoning": "CLI runs locally with no concurrent users. Synchronous API eliminates callback complexity. WAL mode provides concurrent read access for the dashboard while CLI writes.",
132→  "alternatives": [
133→    {"option": "sql.js (WASM build)", "rejected_because": "3x slower for bulk inserts, entire DB in memory, no WAL support"},
134→    {"option": "PostgreSQL via Docker", "rejected_because": "Violates local-first constraint — requires running a server process"}
135→  ],
136→  "trade_offs": "Requires native compilation (node-gyp) which can fail on some systems. No browser compatibility.",
137→  "revisit_when": "If multi-device sync is added or users report node-gyp build failures.",
138→  "confidence": 92,
139→  "evidence": ["User#3: 'We need something that works without a server'", "Assistant#4: 'better-sqlite3 with WAL mode gives concurrent reads...'"]
140→}
141→
142→EXCELLENT learning:
143→{
144→  "title": "Tailwind v4 requires @theme inline{} for CSS variable utilities",
145→  "symptom": "After Tailwind v3→v4 upgrade, custom utilities like bg-primary stopped working. Classes present in HTML but no styles applied.",
146→  "root_cause": "Tailwind v4 removed tailwind.config.js theme extension. CSS variables in :root are not automatically available as utilities — must be registered via @theme inline {} in the CSS file.",
147→  "takeaway": "When migrating Tailwind v3→v4 with shadcn/ui: add @theme inline {} mapping CSS variables, add @custom-variant dark for class-based dark mode, replace tailwindcss-animate with tw-animate-css.",
148→  "applies_when": "Any Tailwind v3→v4 migration using CSS variables for theming, especially with shadcn/ui.",
149→  "confidence": 95,
150→  "evidence": ["User#12: 'The colors are all gone after the upgrade'", "Assistant#13: 'Tailwind v4 requires explicit @theme inline registration...'"]
151→}
152→
153→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
154→
155→/**
156→ * Generate the user prompt for session analysis.
157→ */
158→export function generateSessionAnalysisPrompt(
159→  projectName: string,
160→  sessionSummary: string | null,
161→  formattedMessages: string
162→): string {
163→  return `Analyze this AI coding session and extract insights.
164→
165→Project: ${projectName}
166→${sessionSummary ? `Session Summary: ${sessionSummary}\n` : ''}
167→--- CONVERSATION ---
168→${formattedMessages}
169→--- END CONVERSATION ---
170→
171→Extract insights in this JSON format:
172→{
173→  "session_character": "deep_focus | bug_hunt | feature_build | exploration | refactor | learning | quick_task",
174→  "summary": {
175→    "title": "Brief title describing main accomplishment (max 80 chars)",
176→    "content": "2-4 sentence narrative: what was the goal, what was done, what was the outcome. Mention the primary file or component changed.",
177→    "outcome": "success | partial | abandoned | blocked",
178→    "bullets": ["Each bullet names a specific artifact (file, function, endpoint) and what changed"]
179→  },
180→  "decisions": [
181→    {
182→      "title": "The specific technical choice made (max 80 chars)",
183→      "situation": "What problem or requirement led to this decision point",
184→      "choice": "What was chosen and how it was implemented",
185→      "reasoning": "Why this choice was made — the key factors that tipped the decision",
186→      "alternatives": [
187→        {"option": "Name of alternative", "rejected_because": "Why it was not chosen"}
188→      ],
189→      "trade_offs": "What downsides were accepted, what was given up",
190→      "revisit_when": "Under what conditions this decision should be reconsidered (or 'N/A' if permanent)",
191→      "confidence": 85,
192→      "evidence": ["User#4: quoted text...", "Assistant#5: quoted text..."]
193→    }
194→  ],
195→  "learnings": [
196→    {
197→      "title": "Specific technical discovery or gotcha (max 80 chars)",
198→      "symptom": "What went wrong or was confusing — the observable behavior that triggered investigation",
199→      "root_cause": "The underlying technical reason — why it happened",
200→      "takeaway": "The transferable lesson — what to do or avoid in similar situations, useful outside this project",
201→      "applies_when": "Conditions under which this knowledge is relevant (framework version, configuration, etc.)",
202→      "confidence": 80,
203→      "evidence": ["User#7: quoted text...", "Assistant#8: quoted text..."]
204→    }
205→  ]
206→}
207→
208→Only include insights rated 70+ confidence. If you cannot cite evidence, drop the insight. Return empty arrays for categories with no strong insights. Max 3 decisions, 5 learnings.
209→Evidence should reference the labeled turns in the conversation (e.g., "User#2", "Assistant#5").
210→
211→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
212→}
213→
214→const VALID_SESSION_CHARACTERS = new Set<string>([
215→  'deep_focus', 'bug_hunt', 'feature_build', 'exploration', 'refactor', 'learning', 'quick_task',
216→]);
217→
218→export interface AnalysisResponse {
219→  session_character?: SessionCharacter;
220→  summary: {
221→    title: string;
222→    content: string;
223→    outcome?: 'success' | 'partial' | 'abandoned' | 'blocked';
224→    bullets: string[];
225→  };
226→  decisions: Array<{
227→    title: string;
228→    situation?: string;
229→    choice?: string;
230→    reasoning: string;
231→    alternatives?: Array<{ option: string; rejected_because: string }>;
232→    trade_offs?: string;
233→    revisit_when?: string;
234→    confidence?: number;
235→    evidence?: string[];
236→  }>;
237→  learnings: Array<{
238→    title: string;
239→    symptom?: string;
240→    root_cause?: string;
241→    takeaway?: string;
242→    applies_when?: string;
243→    confidence?: number;
244→    evidence?: string[];
245→  }>;
246→}
247→
248→export interface ParseError {
249→  error_type: 'json_parse_error' | 'no_json_found' | 'invalid_structure';
250→  error_message: string;
251→  response_length: number;
252→  response_preview: string;
253→}
254→
255→function buildResponsePreview(text: string, head = 200, tail = 200): string {
256→  if (text.length <= head + tail + 20) return text;
257→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
258→}
259→
260→export type ParseResult<T> =
261→  | { success: true; data: T }
262→  | { success: false; error: ParseError };
263→
264→function extractJsonPayload(response: string): string | null {
265→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
266→  if (tagged?.[1]) return tagged[1].trim();
267→  const jsonMatch = response.match(/\{[\s\S]*\}/);
268→  return jsonMatch ? jsonMatch[0] : null;
269→}
270→
271→/**
272→ * Parse the LLM response into structured insights.
273→ */
274→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
275→  const response_length = response.length;
276→
277→  const preview = buildResponsePreview(response);
278→
279→  const jsonPayload = extractJsonPayload(response);
280→  if (!jsonPayload) {
281→    console.error('No JSON found in analysis response');
282→    return {
283→      success: false,
284→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
285→    };
286→  }
287→
288→  let parsed: AnalysisResponse;
289→  try {
290→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
291→  } catch {
292→    // Attempt repair — handles trailing commas, unclosed braces, truncated output
293→    try {
294→      parsed = JSON.parse(jsonrepair(jsonPayload)) as AnalysisResponse;
295→    } catch (err) {
296→      const msg = err instanceof Error ? err.message : String(err);
297→      console.error('Failed to parse analysis response (after jsonrepair):', err);
298→      return {
299→        success: false,
300→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
301→      };
302→    }
303→  }
304→
305→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
306→    console.error('Invalid analysis response structure');
307→    return {
308→      success: false,
309→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
310→    };
311→  }
312→
313→  parsed.decisions = parsed.decisions || [];
314→  parsed.learnings = parsed.learnings || [];
315→
316→  // Validate session_character — drop if not a recognized value
317→  if (parsed.session_character && !VALID_SESSION_CHARACTERS.has(parsed.session_character)) {
318→    parsed.session_character = undefined;
319→  }
320→
321→  return { success: true, data: parsed };
322→}
323→
324→// --- Prompt Quality Analysis ---
325→
326→export const PROMPT_QUALITY_SYSTEM_PROMPT = `You are a prompt engineering coach helping developers communicate more effectively with AI coding assistants. You review conversations and identify specific moments where better prompting would have saved time.
327→
328→You will identify:
329→1. **Wasted turns**: User messages that led to clarifications, corrections, or repeated instructions because the original prompt was unclear, missing context, or too vague.
330→2. **Anti-patterns**: Recurring bad habits in the user's prompting style, with specific fixes.
331→3. **Session traits**: Higher-level behavioral patterns about how the session was structured and managed.
332→4. **Efficiency score**: A 0-100 rating of how optimally the user communicated.
333→5. **Actionable tips**: Specific improvements the user can make.
334→
335→Before evaluating, mentally walk through the conversation and identify:
336→1. Each time the assistant asked for clarification that could have been avoided
337→2. Each time the user corrected the assistant's interpretation
338→3. Each time the user repeated an instruction they gave earlier
339→4. Whether the session covers too many unrelated objectives (context drift / session bloat)
340→5. Whether the user provided critical context or requirements late that should have been mentioned upfront
341→6. Whether the user discussed the plan/approach before jumping into implementation, or dove straight into code
342→These are your candidate findings. Only include them if they are genuinely actionable.
343→
344→Guidelines:
345→- Focus on USER messages only — don't critique the assistant's responses
346→- A "wasted turn" is when the user had to send a follow-up message to clarify, correct, or repeat something that could have been included in the original prompt
347→- Only mark a wasted turn if the assistant explicitly asked for clarification or corrected a misunderstanding
348→- Be constructive, not judgmental — the goal is to help users improve
349→- Consider the context: some clarification exchanges are normal and expected
350→- A score of 100 means every user message was perfectly clear and complete
351→- A score of 50 means about half the messages could have been more efficient
352→
353→Length Guidance:
354→- Max 5 wasted turns, max 3 anti-patterns, max 3 session traits, max 5 tips
355→- suggestedRewrite must be a complete, usable prompt — not vague meta-advice
356→- overallAssessment: 2-3 sentences
357→- Total response: stay under 2000 tokens
358→
359→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
360→
361→export function generatePromptQualityPrompt(
362→  projectName: string,
363→  formattedMessages: string,
364→  messageCount: number
365→): string {
366→  return `Analyze the user's prompting efficiency in this AI coding session.
367→
368→Project: ${projectName}
369→Total messages: ${messageCount}
370→
371→--- CONVERSATION ---
372→${formattedMessages}
373→--- END CONVERSATION ---
374→
375→Evaluate the user's prompting quality and respond with this JSON format:
376→{
377→  "efficiencyScore": 75,
378→  "potentialMessageReduction": 3,
379→  "overallAssessment": "2-3 sentence summary of the user's prompting style and efficiency",
380→  "wastedTurns": [
381→    {
382→      "messageIndex": 5,
383→      "originalMessage": "The user's original message (abbreviated if long)",
384→      "whatWentWrong": "What information was missing or ambiguous that caused a follow-up",
385→      "suggestedRewrite": "A concrete rewrite that includes the missing context — must be a complete, usable prompt",
386→      "turnsWasted": 2
387→    }
388→  ],
389→  "antiPatterns": [
390→    {
391→      "name": "Vague Instructions",
392→      "description": "Requests that lack specificity about what file, function, or behavior to change",
393→      "count": 3,
394→      "examples": ["User#2: 'fix it'", "User#5: 'make it work'"],
395→      "fix": "Include the file path, function name, and expected vs actual behavior in the initial request"
396→    }
397→  ],
398→  "sessionTraits": [
399→    {
400→      "trait": "context_drift | objective_bloat | late_context | no_planning | good_structure",
401→      "severity": "high | medium | low",
402→      "description": "What was observed and why it matters",
403→      "evidence": "User#3 switched from auth to styling, then back to auth at User#12",
404→      "suggestion": "Break into separate sessions: one for auth, one for styling"
405→    }
406→  ],
407→  "tips": [
408→    "Always include file paths when asking to modify code",
409→    "Provide error messages verbatim when reporting bugs"
410→  ]
411→}
412→
413→Session trait definitions:
414→- **context_drift**: Session covers too many unrelated objectives, causing the AI to lose context and produce lower quality output
415→- **objective_bloat**: Too many different tasks crammed into one session instead of focused, single-purpose sessions
416→- **late_context**: Critical requirements, constraints, or context provided late in the conversation that should have been mentioned upfront — causing rework or wasted turns
417→- **no_planning**: User jumped straight into implementation without discussing approach, requirements, or plan — leading to course corrections mid-session
418→- **good_structure**: Session was well-structured with clear objectives, upfront context, and logical flow (only include this if truly exemplary)
419→
420→Rules:
421→- messageIndex refers to the 0-based index of the USER message, as labeled in the conversation (e.g., User#0)
422→- Only include genuinely wasted turns, not normal back-and-forth
423→- Tips should be specific and actionable, not generic; include the relevant user message index in parentheses
424→- If the user prompted well, say so — don't manufacture issues
425→- potentialMessageReduction is how many fewer messages the session could have taken with better prompts
426→
427→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
428→}
429→
430→export interface WastedTurn {
431→  messageIndex: number;
432→  originalMessage?: string;
433→  whatWentWrong?: string;
434→  suggestedRewrite: string;
435→  turnsWasted?: number;
436→}
437→
438→export interface AntiPattern {
439→  name: string;
440→  description?: string;
441→  count: number;
442→  examples: string[];
443→  fix?: string;
444→}
445→
446→export interface SessionTrait {
447→  trait: 'context_drift' | 'objective_bloat' | 'late_context' | 'no_planning' | 'good_structure';
448→  severity: 'high' | 'medium' | 'low';
449→  description: string;
450→  evidence?: string;
451→  suggestion?: string;
452→}
453→
454→export interface PromptQualityResponse {
455→  efficiencyScore: number;
456→  potentialMessageReduction: number;
457→  overallAssessment: string;
458→  wastedTurns: WastedTurn[];
459→  antiPatterns: AntiPattern[];
460→  sessionTraits: SessionTrait[];
461→  tips: string[];
462→}
463→
464→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
465→  const response_length = response.length;
466→
467→  const preview = buildResponsePreview(response);
468→
469→  const jsonPayload = extractJsonPayload(response);
470→  if (!jsonPayload) {
471→    console.error('No JSON found in prompt quality response');
472→    return {
473→      success: false,
474→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
475→    };
476→  }
477→
478→  let parsed: PromptQualityResponse;
479→  try {
480→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
481→  } catch {
482→    try {
483→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
484→    } catch (err) {
485→      const msg = err instanceof Error ? err.message : String(err);
486→      console.error('Failed to parse prompt quality response (after jsonrepair):', err);
487→      return {
488→        success: false,
489→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
490→      };
491→    }
492→  }
493→
494→  if (typeof parsed.efficiencyScore !== 'number') {
495→    console.error('Invalid prompt quality response: missing efficiencyScore');
496→    return {
497→      success: false,
498→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiencyScore field', response_length, response_preview: preview },
499→    };
500→  }
501→
502→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
503→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
504→  parsed.overallAssessment = parsed.overallAssessment || '';
505→  parsed.wastedTurns = parsed.wastedTurns || [];
506→  parsed.antiPatterns = parsed.antiPatterns || [];
507→  parsed.sessionTraits = parsed.sessionTraits || [];
508→  parsed.tips = parsed.tips || [];
