  1→// Core analysis engine — server-side.
  2→// Ported from web repo (src/lib/llm/analysis.ts) with SQLite persistence replacing Firestore.
  3→// Key differences from web repo:
  4→//   - Uses SQLiteMessageRow instead of web Message type
  5→//   - Writes insights directly to SQLite via getDb() (not Firestore)
  6→//   - Abort handling uses error.name === 'AbortError' (not DOMException)
  7→//   - Uses session's existing project_id from SQLite (not re-derived hash)
  8→
  9→import { randomUUID } from 'crypto';
 10→import { getDb } from '@code-insights/cli/db/client';
 11→import { createLLMClient, isLLMConfigured } from './client.js';
 12→import {
 13→  SESSION_ANALYSIS_SYSTEM_PROMPT,
 14→  generateSessionAnalysisPrompt,
 15→  formatMessagesForAnalysis,
 16→  parseAnalysisResponse,
 17→  PROMPT_QUALITY_SYSTEM_PROMPT,
 18→  generatePromptQualityPrompt,
 19→  parsePromptQualityResponse,
 20→  type SQLiteMessageRow,
 21→  type AnalysisResponse,
 22→  type PromptQualityResponse,
 23→  type ParseError,
 24→} from './prompts.js';
 25→
 26→// Re-export SQLiteMessageRow so routes can import it from analysis.ts directly
 27→export type { SQLiteMessageRow };
 28→
 29→// Maximum tokens to send to LLM (leaving room for response)
 30→const MAX_INPUT_TOKENS = 80000;
 31→const ANALYSIS_VERSION = '3.0.0';
 32→
 33→export interface AnalysisProgress {
 34→  phase: 'loading_messages' | 'analyzing' | 'saving';
 35→  currentChunk?: number;
 36→  totalChunks?: number;
 37→}
 38→
 39→export interface AnalysisOptions {
 40→  onProgress?: (progress: AnalysisProgress) => void;
 41→  signal?: AbortSignal;
 42→}
 43→
 44→export interface AnalysisResult {
 45→  success: boolean;
 46→  insights: InsightRow[];
 47→  error?: string;
 48→  error_type?: string;
 49→  response_length?: number;
 50→  response_preview?: string;
 51→  usage?: {
 52→    inputTokens: number;
 53→    outputTokens: number;
 54→  };
 55→}
 56→
 57→// Re-export ParseError so routes can import it from analysis.ts
 58→export type { ParseError };
 59→
 60→// Shape of a saved insight row (matches the SQLite schema)
 61→export interface InsightRow {
 62→  id: string;
 63→  session_id: string;
 64→  project_id: string;
 65→  project_name: string;
 66→  type: string;
 67→  title: string;
 68→  content: string;
 69→  summary: string;
 70→  bullets: string;           // JSON-encoded string[]
 71→  confidence: number;
 72→  source: 'llm';
 73→  metadata: string | null;   // JSON-encoded object
 74→  timestamp: string;         // ISO 8601
 75→  created_at: string;        // ISO 8601
 76→  scope: string;
 77→  analysis_version: string;
 78→}
 79→
 80→// Minimal session data needed for analysis (from SQLite sessions row)
 81→export interface SessionData {
 82→  id: string;
 83→  project_id: string;
 84→  project_name: string;
 85→  project_path: string;
 86→  summary: string | null;
 87→  ended_at: string;          // ISO 8601
 88→}
 89→
 90→/**
 91→ * Analyze a session and generate insights, saving them to SQLite.
 92→ */
 93→export async function analyzeSession(
 94→  session: SessionData,
 95→  messages: SQLiteMessageRow[],
 96→  options?: AnalysisOptions
 97→): Promise<AnalysisResult> {
 98→  if (!isLLMConfigured()) {
 99→    return {
100→      success: false,
101→      insights: [],
102→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
103→    };
104→  }
105→
106→  if (messages.length === 0) {
107→    return {
108→      success: false,
109→      insights: [],
110→      error: 'No messages found for this session.',
111→    };
112→  }
113→
114→  try {
115→    const client = createLLMClient();
116→    const formattedMessages = formatMessagesForAnalysis(messages);
117→    const estimatedTokens = client.estimateTokens(formattedMessages);
118→
119→    let analysisResponse: AnalysisResponse;
120→    let totalInputTokens = 0;
121→    let totalOutputTokens = 0;
122→
123→    if (estimatedTokens > MAX_INPUT_TOKENS) {
124→      // Chunk the messages and analyze separately
125→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
126→      const chunkResponses: AnalysisResponse[] = [];
127→      const totalChunks = chunks.length;
128→
129→      for (let i = 0; i < chunks.length; i++) {
130→        const chunk = chunks[i];
131→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
132→
133→        const chunkFormatted = formatMessagesForAnalysis(chunk);
134→        const prompt = generateSessionAnalysisPrompt(
135→          session.project_name,
136→          session.summary,
137→          chunkFormatted
138→        );
139→
140→        const response = await client.chat([
141→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
142→          { role: 'user', content: prompt },
143→        ], { signal: options?.signal });
144→
145→        if (response.usage) {
146→          totalInputTokens += response.usage.inputTokens;
147→          totalOutputTokens += response.usage.outputTokens;
148→        }
149→
150→        const parsed = parseAnalysisResponse(response.content);
151→        if (parsed.success) chunkResponses.push(parsed.data);
152→      }
153→
154→      if (chunkResponses.length === 0) {
155→        return {
156→          success: false,
157→          insights: [],
158→          error: 'All chunks failed to parse LLM response',
159→          error_type: 'json_parse_error',
160→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
161→        };
162→      }
163→
164→      analysisResponse = mergeAnalysisResponses(chunkResponses);
165→    } else {
166→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
167→      const prompt = generateSessionAnalysisPrompt(
168→        session.project_name,
169→        session.summary,
170→        formattedMessages
171→      );
172→
173→      const response = await client.chat([
174→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
175→        { role: 'user', content: prompt },
176→      ], { signal: options?.signal });
177→
178→      if (response.usage) {
179→        totalInputTokens = response.usage.inputTokens;
180→        totalOutputTokens = response.usage.outputTokens;
181→      }
182→
183→      const parsed = parseAnalysisResponse(response.content);
184→      if (!parsed.success) {
185→        return {
186→          success: false,
187→          insights: [],
188→          error: 'Failed to parse LLM response. Please try again.',
189→          error_type: parsed.error.error_type,
190→          response_length: parsed.error.response_length,
191→          response_preview: parsed.error.response_preview,
192→        };
193→      }
194→
195→      analysisResponse = parsed.data;
196→    }
197→
198→    options?.onProgress?.({ phase: 'saving' });
199→    const insights = convertToInsightRows(analysisResponse, session);
200→
201→    // Save new insights first, then delete old non-prompt-quality insights
202→    // (safe order: if save fails, old data is preserved)
203→    saveInsightsToDb(insights);
204→    deleteSessionInsights(session.id, {
205→      excludeTypes: ['prompt_quality'],
206→      excludeIds: insights.map(i => i.id),
207→    });
208→
209→    // Update session character if LLM classified it
210→    if (analysisResponse.session_character) {
211→      const db = getDb();
212→      db.prepare('UPDATE sessions SET session_character = ? WHERE id = ?')
213→        .run(analysisResponse.session_character, session.id);
214→    }
215→
216→    return {
217→      success: true,
218→      insights,
219→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
220→    };
221→  } catch (error) {
222→    if (error instanceof Error && error.name === 'AbortError') {
223→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
224→    }
225→    return {
226→      success: false,
227→      insights: [],
228→      error: error instanceof Error ? error.message : 'Analysis failed',
229→      error_type: 'api_error',
230→    };
231→  }
232→}
233→
234→/**
235→ * Analyze prompt quality for a session.
236→ */
237→export async function analyzePromptQuality(
238→  session: SessionData,
239→  messages: SQLiteMessageRow[],
240→  options?: AnalysisOptions
241→): Promise<AnalysisResult> {
242→  if (!isLLMConfigured()) {
243→    return {
244→      success: false,
245→      insights: [],
246→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
247→    };
248→  }
249→
250→  if (messages.length === 0) {
251→    return {
252→      success: false,
253→      insights: [],
254→      error: 'No messages found for this session.',
255→    };
256→  }
257→
258→  const userMessages = messages.filter(m => m.type === 'user');
259→  if (userMessages.length < 2) {
260→    return {
261→      success: false,
262→      insights: [],
263→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
264→    };
265→  }
266→
267→  try {
268→    const client = createLLMClient();
269→    const formattedMessages = formatMessagesForAnalysis(messages);
270→
271→    let analysisInput = formattedMessages;
272→    const estimatedTokens = client.estimateTokens(formattedMessages);
273→    if (estimatedTokens > MAX_INPUT_TOKENS) {
274→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
275→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
276→    }
277→
278→    const prompt = generatePromptQualityPrompt(
279→      session.project_name,
280→      analysisInput,
281→      messages.length
282→    );
283→
284→    options?.onProgress?.({ phase: 'analyzing' });
285→    const response = await client.chat([
286→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
287→      { role: 'user', content: prompt },
288→    ], { signal: options?.signal });
289→
290→    const parsed = parsePromptQualityResponse(response.content);
291→    if (!parsed.success) {
292→      return {
293→        success: false,
294→        insights: [],
295→        error: 'Failed to parse prompt quality analysis. Please try again.',
296→        error_type: parsed.error.error_type,
297→        response_length: parsed.error.response_length,
298→        response_preview: parsed.error.response_preview,
299→      };
300→    }
301→
302→    options?.onProgress?.({ phase: 'saving' });
303→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
304→
305→    // Save new insight, then delete old prompt_quality insights
306→    saveInsightsToDb([insight]);
307→    deleteSessionInsights(session.id, {
308→      includeOnlyTypes: ['prompt_quality'],
309→      excludeIds: [insight.id],
310→    });
311→
312→    return {
313→      success: true,
314→      insights: [insight],
315→      usage: response.usage ? {
316→        inputTokens: response.usage.inputTokens,
317→        outputTokens: response.usage.outputTokens,
318→      } : undefined,
319→    };
320→  } catch (error) {
321→    if (error instanceof Error && error.name === 'AbortError') {
322→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
323→    }
324→    return {
325→      success: false,
326→      insights: [],
327→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
328→      error_type: 'api_error',
329→    };
330→  }
331→}
332→
333→export interface RecurringInsightGroup {
334→  insightIds: string[];
335→  theme: string;
336→}
337→
338→export interface RecurringInsightResult {
339→  success: boolean;
340→  groups: RecurringInsightGroup[];
341→  updatedCount: number;
342→  error?: string;
343→  usage?: {
344→    inputTokens: number;
345→    outputTokens: number;
346→  };
347→}
348→
349→/**
350→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
351→ */
352→export async function findRecurringInsights(
353→  insights: Array<{
354→    id: string;
355→    type: string;
356→    title: string;
357→    summary: string;
358→    project_name: string;
359→    session_id: string;
360→  }>
361→): Promise<RecurringInsightResult> {
362→  if (!isLLMConfigured()) {
363→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
364→  }
365→
366→  const candidates = insights
367→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
368→    .slice(0, 200);
369→
370→  if (candidates.length < 2) {
371→    return {
372→      success: false,
373→      groups: [],
374→      updatedCount: 0,
375→      error: 'Need at least 2 non-summary insights to find patterns.',
376→    };
377→  }
378→
379→  try {
380→    const client = createLLMClient();
381→
382→    const insightData = candidates.map(i => ({
383→      id: i.id,
384→      type: i.type === 'technique' ? 'learning' : i.type,
385→      title: i.title,
386→      summary: i.summary.slice(0, 150),
387→      projectName: i.project_name,
388→      sessionId: i.session_id,
389→    }));
390→
391→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
392→
393→RULES:
394→- Only group insights that are genuinely about the same concept/topic
395→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
396→- A group must have at least 2 insights
397→- An insight can only belong to one group
398→- Provide a brief "theme" describing what the group shares
399→- If no recurring patterns exist, return an empty groups array
400→
401→INSIGHTS:
402→${JSON.stringify(insightData, null, 2)}
403→
404→Respond with valid JSON only:
405→{
406→  "groups": [
407→    {
408→      "insightIds": ["insight_abc", "insight_def"],
409→      "theme": "Brief description of the shared concept"
410→    }
411→  ]
412→}`;
413→
414→    const response = await client.chat([
415→      {
416→        role: 'system',
417→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
418→      },
419→      { role: 'user', content: prompt },
420→    ]);
421→
422→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
423→    if (!jsonMatch) {
424→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
425→    }
426→
427→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
428→    const groups = parsed.groups || [];
429→
430→    const validIds = new Set(candidates.map(i => i.id));
431→    const validGroups = groups
432→      .map(g => ({
433→        ...g,
434→        insightIds: g.insightIds.filter(id => validIds.has(id)),
435→      }))
436→      .filter(g => g.insightIds.length >= 2);
437→
438→    if (validGroups.length === 0) {
439→      return {
440→        success: true,
441→        groups: [],
442→        updatedCount: 0,
443→        usage: response.usage
444→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
445→          : undefined,
446→      };
447→    }
448→
449→    // Build bidirectional links
450→    const linkMap = new Map<string, string[]>();
451→    for (const group of validGroups) {
452→      for (const id of group.insightIds) {
453→        const others = group.insightIds.filter(otherId => otherId !== id);
454→        const existing = linkMap.get(id) || [];
455→        linkMap.set(id, [...new Set([...existing, ...others])]);
456→      }
457→    }
458→
459→    // Write links to SQLite
460→    const db = getDb();
461→    const updateLinks = db.prepare(
462→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
463→    );
464→
465→    for (const [insightId, linkedIds] of linkMap.entries()) {
466→      updateLinks.run(JSON.stringify(linkedIds), insightId);
467→    }
468→
469→    return {
470→      success: true,
471→      groups: validGroups,
472→      updatedCount: linkMap.size,
473→      usage: response.usage
474→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
475→        : undefined,
476→    };
477→  } catch (error) {
478→    return {
479→      success: false,
480→      groups: [],
481→      updatedCount: 0,
482→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
483→    };
484→  }
485→}
486→
487→// --- Internal helpers ---
488→
489→function chunkMessages(
490→  messages: SQLiteMessageRow[],
491→  estimateTokens: (text: string) => number
492→): SQLiteMessageRow[][] {
493→  const chunks: SQLiteMessageRow[][] = [];
494→  let currentChunk: SQLiteMessageRow[] = [];
495→  let currentTokens = 0;
496→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
497→
498→  for (const message of messages) {
499→    let toolResults: Array<{ output?: string }> = [];
500→    try {
501→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
502→    } catch {
503→      toolResults = [];
504→    }
505→
506→    const messageText = [
507→      message.content,
508→      message.thinking?.slice(0, 1000) ?? '',
509→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
510→    ].join(' ');
511→    const messageTokens = estimateTokens(messageText);
512→
513→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
514→      chunks.push(currentChunk);
515→      currentChunk = [];
516→      currentTokens = 0;
517→    }
518→
519→    currentChunk.push(message);
520→    currentTokens += messageTokens;
521→  }
522→
523→  if (currentChunk.length > 0) {
524→    chunks.push(currentChunk);
525→  }
526→
527→  return chunks;
528→}
529→
530→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
531→  if (responses.length === 0) {
532→    return {
533→      summary: { title: 'Analysis failed', content: '', bullets: [] },
534→      decisions: [],
535→      learnings: [],
536→    };
537→  }
538→
539→  if (responses.length === 1) return responses[0];
540→
541→  const merged: AnalysisResponse = {
542→    session_character: responses.find(r => r.session_character)?.session_character,
543→    summary: responses[0].summary,
544→    decisions: [],
545→    learnings: [],
546→  };
547→
548→  for (const response of responses) {
549→    merged.decisions.push(...response.decisions);
550→    merged.learnings.push(...response.learnings);
551→  }
552→
553→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
554→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
555→
556→  return merged;
557→}
558→
559→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
560→  const seen = new Set<string>();
561→  return items.filter((item) => {
562→    const normalized = item.title.toLowerCase().trim();
563→    if (seen.has(normalized)) return false;
564→    seen.add(normalized);
565→    return true;
566→  });
567→}
568→
569→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
570→  const insights: InsightRow[] = [];
571→  const now = new Date().toISOString();
572→
573→  insights.push({
574→    id: randomUUID(),
575→    session_id: session.id,
576→    project_id: session.project_id,
577→    project_name: session.project_name,
578→    type: 'summary',
579→    title: response.summary.title,
580→    content: response.summary.content,
581→    summary: response.summary.content,
582→    bullets: JSON.stringify(response.summary.bullets),
583→    confidence: 0.9,
584→    source: 'llm',
585→    metadata: response.summary.outcome
586→      ? JSON.stringify({ outcome: response.summary.outcome })
587→      : null,
588→    timestamp: session.ended_at,
589→    created_at: now,
590→    scope: 'session',
591→    analysis_version: ANALYSIS_VERSION,
592→  });
593→
594→  for (const decision of response.decisions) {
595→    const confidence = decision.confidence ?? 85;
596→    if (confidence < 70) continue;
597→
598→    const content = decision.situation && decision.choice
599→      ? `${decision.situation} → ${decision.choice}`
600→      : decision.choice || decision.situation || decision.title;
601→
602→    const altBullets = (decision.alternatives || [])
603→      .filter(a => a && typeof a === 'object' && a.option)
604→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
605→
606→    insights.push({
607→      id: randomUUID(),
608→      session_id: session.id,
609→      project_id: session.project_id,
610→      project_name: session.project_name,
611→      type: 'decision',
612→      title: decision.title,
613→      content,
614→      summary: (decision.choice || content).slice(0, 200),
615→      bullets: JSON.stringify(altBullets),
616→      confidence: confidence / 100,
617→      source: 'llm',
618→      metadata: JSON.stringify({
619→        situation: decision.situation,
620→        choice: decision.choice,
621→        reasoning: decision.reasoning,
622→        alternatives: decision.alternatives,
623→        trade_offs: decision.trade_offs,
624→        revisit_when: decision.revisit_when,
625→        evidence: decision.evidence,
626→      }),
627→      timestamp: session.ended_at,
628→      created_at: now,
629→      scope: 'session',
630→      analysis_version: ANALYSIS_VERSION,
631→    });
632→  }
633→
634→  for (const learning of response.learnings) {
635→    const confidence = learning.confidence ?? 80;
636→    if (confidence < 70) continue;
637→
638→    const content = learning.takeaway || learning.title;
639→
640→    insights.push({
641→      id: randomUUID(),
642→      session_id: session.id,
643→      project_id: session.project_id,
644→      project_name: session.project_name,
645→      type: 'learning',
646→      title: learning.title,
647→      content,
648→      summary: content.slice(0, 200),
649→      bullets: JSON.stringify([]),
650→      confidence: confidence / 100,
651→      source: 'llm',
652→      metadata: JSON.stringify({
653→        symptom: learning.symptom,
654→        root_cause: learning.root_cause,
655→        takeaway: learning.takeaway,
656→        applies_when: learning.applies_when,
657→        evidence: learning.evidence,
658→      }),
659→      timestamp: session.ended_at,
660→      created_at: now,
661→      scope: 'session',
662→      analysis_version: ANALYSIS_VERSION,
663→    });
664→  }
665→
666→  return insights;
667→}
668→
669→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
670→  const now = new Date().toISOString();
671→
672→  return {
673→    id: randomUUID(),
674→    session_id: session.id,
675→    project_id: session.project_id,
676→    project_name: session.project_name,
677→    type: 'prompt_quality',
678→    title: `Prompt Efficiency: ${response.efficiencyScore}/100`,
679→    content: response.overallAssessment,
680→    summary: response.overallAssessment,
681→    bullets: JSON.stringify(response.tips),
682→    confidence: 0.85,
683→    source: 'llm',
684→    metadata: JSON.stringify({
685→      efficiencyScore: response.efficiencyScore,
686→      wastedTurns: response.wastedTurns,
687→      antiPatterns: response.antiPatterns,
688→      sessionTraits: response.sessionTraits,
689→      potentialMessageReduction: response.potentialMessageReduction,
690→    }),
691→    timestamp: session.ended_at,
692→    created_at: now,
693→    scope: 'session',
694→    analysis_version: ANALYSIS_VERSION,
695→  };
696→}
697→
698→/**
699→ * Write insight rows to SQLite using prepared statements.
700→ */
701→function saveInsightsToDb(insights: InsightRow[]): void {
702→  const db = getDb();
703→  const insert = db.prepare(`
704→    INSERT OR REPLACE INTO insights (
705→      id, session_id, project_id, project_name, type, title, content,
706→      summary, bullets, confidence, source, metadata, timestamp,
707→      created_at, scope, analysis_version
708→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
709→  `);
710→
711→  const insertMany = db.transaction((rows: InsightRow[]) => {
712→    for (const row of rows) {
713→      insert.run(
714→        row.id,
715→        row.session_id,
716→        row.project_id,
717→        row.project_name,
718→        row.type,
719→        row.title,
720→        row.content,
721→        row.summary,
722→        row.bullets,
723→        row.confidence,
724→        row.source,
725→        row.metadata,
726→        row.timestamp,
727→        row.created_at,
728→        row.scope,
729→        row.analysis_version,
730→      );
731→    }
732→  });
733→
734→  insertMany(insights);
735→}
736→
737→interface DeleteOptions {
738→  excludeTypes?: string[];
739→  includeOnlyTypes?: string[];
740→  excludeIds?: string[];
741→}
742→
743→/**
744→ * Delete insights for a session, with optional type and ID exclusions.
745→ */
746→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
747→  const db = getDb();
748→  const conditions: string[] = ['session_id = ?'];
749→  const params: (string | number)[] = [sessionId];
750→
751→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
752→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
753→    params.push(...opts.excludeTypes);
754→  }
755→
756→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
757→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
758→    params.push(...opts.includeOnlyTypes);
759→  }
760→
761→  if (opts.excludeIds && opts.excludeIds.length > 0) {
762→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
763→    params.push(...opts.excludeIds);
764→  }
765→
766→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
767→}
