  1→import { serve } from '@hono/node-server';
  2→import { serveStatic } from '@hono/node-server/serve-static';
  3→import { Hono } from 'hono';
  4→import { existsSync, readFileSync } from 'fs';
  5→import { relative, join } from 'path';
  6→import { openUrl } from '@code-insights/cli/utils/browser';
  7→import { shutdownTelemetry } from '@code-insights/cli/utils/telemetry';
  8→import projectsRouter from './routes/projects.js';
  9→import sessionsRouter from './routes/sessions.js';
 10→import messagesRouter from './routes/messages.js';
 11→import insightsRouter from './routes/insights.js';
 12→import analysisRouter from './routes/analysis.js';
 13→import analyticsRouter from './routes/analytics.js';
 14→import configRouter from './routes/config.js';
 15→import exportRouter from './routes/export.js';
 16→import telemetryRouter from './routes/telemetry.js';
 17→
 18→export interface ServerOptions {
 19→  port: number;
 20→  // Absolute path to the dashboard/dist directory
 21→  staticDir: string;
 22→  openBrowser: boolean;
 23→}
 24→
 25→/**
 26→ * Create the Hono app with all API routes mounted.
 27→ * Does NOT add static file serving or call serve() — that's startServer's job.
 28→ * Exported so tests can use app.request() without starting a real server.
 29→ */
 30→export function createApp(): Hono {
 31→  const app = new Hono();
 32→
 33→  // Global error handler — prevents stack trace leakage to clients.
 34→  // Detects malformed JSON bodies (SyntaxError) and returns 400 instead of 500.
 35→  app.onError((err, c) => {
 36→    if (err instanceof SyntaxError && err.message.includes('JSON')) {
 37→      return c.json({ error: 'Invalid JSON in request body' }, 400);
 38→    }
 39→    console.error(err);
 40→    return c.json({ error: 'Internal server error' }, 500);
 41→  });
 42→
 43→  // API routes — all under /api
 44→  app.route('/api/projects', projectsRouter);
 45→  app.route('/api/sessions', sessionsRouter);
 46→  app.route('/api/messages', messagesRouter);
 47→  app.route('/api/insights', insightsRouter);
 48→  app.route('/api/analysis', analysisRouter);
 49→  app.route('/api/analytics', analyticsRouter);
 50→  app.route('/api/config', configRouter);
 51→  app.route('/api/export', exportRouter);
 52→  app.route('/api/telemetry', telemetryRouter);
 53→
 54→  // Health check
 55→  app.get('/api/health', (c) => c.json({ ok: true, version: '0.1.0' }));
 56→
 57→  // API 404 catch-all — must come AFTER all /api sub-routers and BEFORE static serving.
 58→  // Without this, unmatched /api/* routes fall through to the SPA fallback and return
 59→  // index.html as 200, which breaks API clients expecting JSON errors.
 60→  app.all('/api/*', (c) => c.json({ error: 'Not found' }, 404));
 61→
 62→  return app;
 63→}
 64→
 65→/**
 66→ * Start the Code Insights local dashboard server.
 67→ * Calls createApp(), adds static file serving + SPA fallback if staticDir exists,
 68→ * then calls serve().
 69→ * Called by the CLI `dashboard` command.
 70→ */
 71→export async function startServer(options: ServerOptions): Promise<void> {
 72→  const { port, staticDir, openBrowser } = options;
 73→
 74→  const app = createApp();
 75→
 76→  // Static file serving — only if the dashboard has been built.
 77→  // serveStatic requires a path relative to process.cwd(), not an absolute path.
 78→  if (existsSync(staticDir)) {
 79→    const relativeStaticDir = relative(process.cwd(), staticDir);
 80→    app.use('/*', serveStatic({ root: relativeStaticDir }));
 81→
 82→    // Cache index.html at startup — avoids a readFileSync on every SPA navigation
 83→    // request, which would be a pointless disk read for a file that never changes
 84→    // while the server is running.
 85→    const indexPath = join(staticDir, 'index.html');
 86→    const indexHtml = existsSync(indexPath) ? readFileSync(indexPath, 'utf-8') : null;
 87→
 88→    // SPA fallback: any non-API route not matched by serveStatic serves index.html
 89→    // so react-router can handle client-side routing.
 90→    app.get('*', (c) => {
 91→      if (indexHtml) return c.html(indexHtml);
 92→      return c.text('Dashboard not found. Run pnpm build first.', 404);
 93→    });
 94→  } else {
 95→    // Dashboard not built — serve a helpful message
 96→    app.get('*', (c) =>
 97→      c.html(`
 98→        <html><body style="font-family:monospace;padding:2rem">
 99→          <h2>Code Insights Dashboard</h2>
100→          <p>The dashboard has not been built yet.</p>
101→          <pre>pnpm install &amp;&amp; pnpm build</pre>
102→          <p>Then restart the server.</p>
103→        </body></html>
104→      `),
105→    );
106→  }
107→
108→  // Graceful shutdown: flush PostHog events before exit, then let the process
109→  // 'exit' handler in cli/src/db/client.ts run WAL checkpoint via closeDb().
110→  // 3s timeout guards against PostHog SDK stalling on network issues.
111→  const shutdown = async () => {
112→    await Promise.race([
113→      shutdownTelemetry(),
114→      new Promise<void>((resolve) => setTimeout(resolve, 3000)),
115→    ]);
116→    process.exit(0);
117→  };
118→  process.on('SIGINT', () => { void shutdown(); });
119→  process.on('SIGTERM', () => { void shutdown(); });
120→
121→  serve({ fetch: app.fetch, port }, (info) => {
122→    const url = `http://localhost:${info.port}`;
123→    console.log(`  Code Insights dashboard running at ${url}`);
124→    if (openBrowser) {
125→      openUrl(url);
126→    }
127→  });
128→}
