```typescript
// POST /api/analysis/facets
// Body: { sessionId: string }
// Extracts facets only for a session that was already analyzed (backfill).
app.post('/facets', async (c) => {
  if (!isLLMConfigured()) {
    return c.json({ success: false, error: 'LLM not configured.' }, 400);
  }

  const body = await c.req.json<{ sessionId?: string }>();
  if (!body.sessionId) {
    return c.json({ error: 'Missing required field: sessionId' }, 400);
  }

  const db = getDb();

  // Check if facets already exist
  const existing = db.prepare('SELECT 1 FROM session_facets WHERE session_id = ?').get(body.sessionId);
  if (existing) {
    return c.json({ success: true, message: 'Facets already exist for this session.' });
  }

  const session = db.prepare(`
    SELECT id, project_id, project_name, project_path, summary, ended_at
    FROM sessions WHERE id = ?
  `).get(body.sessionId) as SessionData | undefined;

  if (!session) {
    return c.json({ error: 'Session not found' }, 404);
  }

  const messages = db.prepare(`
    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
  `).all(body.sessionId) as SQLiteMessageRow[];

  if (messages.length === 0) {
    return c.json({ success: false, error: 'No messages found.' }, 400);
  }

  try {
    const { createLLMClient } = await import('../llm/client.js');
    const { FACET_ONLY_SYSTEM_PROMPT, generateFacetOnlyPrompt } = await import('../llm/facet-prompts.js');

    const client = createLLMClient();
    const prompt = generateFacetOnlyPrompt(session.project_name, session.summary, messages);

    const response = await client.chat([
      { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
      { role: 'user', content: prompt },
    ]);

    const jsonPayload = response.content.match(/<json>\s*([\s\S]*?)\s*<\/json>/i)?.[1]
      || response.content.match(/\{[\s\S]*\}/)?.[0];

    if (!jsonPayload) {
      return c.json({ success: false, error: 'Failed to parse facet response.' }, 500);
    }

    const facets = JSON.parse(jsonPayload);

    db.prepare(`
      INSERT OR REPLACE INTO session_facets (
        session_id, outcome_satisfaction, workflow_pattern,
        had_course_correction, course_correction_reason,
        iteration_count, friction_points, effective_patterns,
        extracted_at, analysis_version
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), '3.0.0')
    `).run(
      session.id,
      facets.outcome_satisfaction || 'medium',
      facets.workflow_pattern || null,
      facets.had_course_correction ? 1 : 0,
      facets.course_correction_reason || null,
      facets.iteration_count || 0,
      JSON.stringify((facets.friction_points || []).slice(0, 5)),
      JSON.stringify((facets.effective_patterns || []).slice(0, 3)),
    );

    return c.json({
      success: true,
      usage: response.usage ? {
        inputTokens: response.usage.inputTokens,
        outputTokens: response.usage.outputTokens,
      } : undefined,
    });
  } catch (error) {
    return c.json({
      success: false,
      error: error instanceof Error ? error.message : 'Facet extraction failed',
    }, 500);
  }
});
```

