// GET /api/analysis/facet-coverage
// Query: projectId?, period? (ISO date string)
// Returns count of sessions with/without facets
app.get('/facet-coverage', (c) => {
  const db = getDb();
  const { projectId, since } = c.req.query();

  const conditions: string[] = [];
  const params: string[] = [];

  if (projectId) {
    conditions.push('s.project_id = ?');
    params.push(projectId);
  }
  if (since) {
    conditions.push('s.started_at >= ?');
    params.push(since);
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

  const result = db.prepare(`
    SELECT
      COUNT(*) as total_sessions,
      COUNT(sf.session_id) as sessions_with_facets
    FROM sessions s
    LEFT JOIN session_facets sf ON s.id = sf.session_id
    ${where}
  `).get(...params) as { total_sessions: number; sessions_with_facets: number };

  return c.json({
    totalSessions: result.total_sessions,
    sessionsWithFacets: result.sessions_with_facets,
    sessionsMissingFacets: result.total_sessions - result.sessions_with_facets,
    coveragePercent: result.total_sessions > 0
      ? Math.round((result.sessions_with_facets / result.total_sessions) * 100)
      : 100,
  });
});
