```typescript
import { Hono } from 'hono';
import { getDb } from '@code-insights/cli/db/client';

const app = new Hono();

// GET /api/facets/aggregate
// Query: projectId?, since? (ISO date), source?
// Returns pre-aggregated facet data for the Patterns page
app.get('/aggregate', (c) => {
  const db = getDb();
  const { projectId, since, source } = c.req.query();

  const conditions: string[] = [];
  const params: (string | number)[] = [];

  if (projectId) {
    conditions.push('s.project_id = ?');
    params.push(projectId);
  }
  if (since) {
    conditions.push('s.started_at >= ?');
    params.push(since);
  }
  if (source) {
    conditions.push('s.source_tool = ?');
    params.push(source);
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

  // 1. Get all facets in range
  const facetRows = db.prepare(`
    SELECT sf.*, s.session_character, s.source_tool, s.started_at, s.project_name
    FROM session_facets sf
    JOIN sessions s ON sf.session_id = s.id
    ${where}
    ORDER BY s.started_at DESC
  `).all(...params) as Array<{
    session_id: string;
    outcome_satisfaction: string;
    workflow_pattern: string | null;
    had_course_correction: number;
    course_correction_reason: string | null;
    iteration_count: number;
    friction_points: string;
    effective_patterns: string;
    session_character: string | null;
    source_tool: string;
    started_at: string;
    project_name: string;
  }>;

  // 2. Aggregate friction categories via code (not LLM)
  const frictionAgg = new Map<string, { count: number; highCount: number; mediumCount: number; lowCount: number; resolvedCount: number; unresolvedCount: number; examples: string[] }>();

  for (const row of facetRows) {
    const points = JSON.parse(row.friction_points || '[]') as Array<{ category: string; description: string; severity: string; resolution: string }>;
    for (const fp of points) {
      const existing = frictionAgg.get(fp.category) || { count: 0, highCount: 0, mediumCount: 0, lowCount: 0, resolvedCount: 0, unresolvedCount: 0, examples: [] };
      existing.count++;
      if (fp.severity === 'high') existing.highCount++;
      else if (fp.severity === 'medium') existing.mediumCount++;
      else existing.lowCount++;
      if (fp.resolution === 'resolved') existing.resolvedCount++;
      else if (fp.resolution === 'unresolved') existing.unresolvedCount++;
      if (existing.examples.length < 3) existing.examples.push(fp.description);
      frictionAgg.set(fp.category, existing);
    }
  }

  // 3. Aggregate effective patterns
  const patternAgg = new Map<string, { count: number; totalConfidence: number; descriptions: string[] }>();
  for (const row of facetRows) {
    const patterns = JSON.parse(row.effective_patterns || '[]') as Array<{ description: string; confidence: number }>;
    for (const ep of patterns) {
      // Simple grouping by first 50 chars (exact dedup)
      const key = ep.description.slice(0, 50).toLowerCase();
      const existing = patternAgg.get(key) || { count: 0, totalConfidence: 0, descriptions: [] };
      existing.count++;
      existing.totalConfidence += ep.confidence;
      if (existing.descriptions.length < 3) existing.descriptions.push(ep.description);
      patternAgg.set(key, existing);
    }
  }

  // 4. Aggregate workflow patterns (scalar — already indexed)
  const workflowDist = db.prepare(`
    SELECT sf.workflow_pattern, COUNT(*) as count
    FROM session_facets sf
    JOIN sessions s ON sf.session_id = s.id
    ${where}
    AND sf.workflow_pattern IS NOT NULL
    GROUP BY sf.workflow_pattern
    ORDER BY count DESC
  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;

  // 5. Aggregate outcome satisfaction (scalar — already indexed)
  const outcomeDist = db.prepare(`
    SELECT sf.outcome_satisfaction, COUNT(*) as count
    FROM session_facets sf
    JOIN sessions s ON sf.session_id = s.id
    ${where}
    GROUP BY sf.outcome_satisfaction
    ORDER BY count DESC
  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;

  // 6. Session character distribution (from sessions table)
  const characterDist = db.prepare(`
    SELECT s.session_character, COUNT(*) as count
    FROM sessions s
    JOIN session_facets sf ON s.id = sf.session_id
    ${where}
    AND s.session_character IS NOT NULL
    GROUP BY s.session_character
    ORDER BY count DESC
  `).all(...params) as Array<{ session_character: string; count: number }>;

  // 7. Course corrections
  const courseCorrections = facetRows.filter(r => r.had_course_correction === 1);

  return c.json({
    totalSessions: facetRows.length,
    friction: Array.from(frictionAgg.entries())
      .map(([category, data]) => ({ category, ...data }))
      .sort((a, b) => (b.count * (b.highCount + 1)) - (a.count * (a.highCount + 1))),
    effectivePatterns: Array.from(patternAgg.entries())
      .map(([_key, data]) => ({
        description: data.descriptions[0],
        count: data.count,
        avgConfidence: Math.round(data.totalConfidence / data.count),
        examples: data.descriptions,
      }))
      .sort((a, b) => b.count - a.count),
    workflowDistribution: workflowDist,
    outcomeDistribution: outcomeDist,
    characterDistribution: characterDist,
    courseCorrections: {
      count: courseCorrections.length,
      percent: facetRows.length > 0 ? Math.round((courseCorrections.length / facetRows.length) * 100) : 0,
      reasons: courseCorrections
        .filter(r => r.course_correction_reason)
        .map(r => r.course_correction_reason!)
        .slice(0, 5),
    },
    avgIterationCount: facetRows.length > 0
      ? Math.round(facetRows.reduce((sum, r) => sum + r.iteration_count, 0) / facetRows.length * 10) / 10
      : 0,
