248→export interface ParseError {
249→  error_type: 'json_parse_error' | 'no_json_found' | 'invalid_structure';
250→  error_message: string;
251→  response_length: number;
252→  response_preview: string;
253→}
254→
255→function buildResponsePreview(text: string, head = 200, tail = 200): string {
256→  if (text.length <= head + tail + 20) return text;
257→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
258→}
259→
260→export type ParseResult<T> =
261→  | { success: true; data: T }
262→  | { success: false; error: ParseError };
263→
264→function extractJsonPayload(response: string): string | null {
265→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
266→  if (tagged?.[1]) return tagged[1].trim();
267→  const jsonMatch = response.match(/\{[\s\S]*\}/);
268→  return jsonMatch ? jsonMatch[0] : null;
269→}
270→
271→/**
272→ * Parse the LLM response into structured insights.
273→ */
274→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
275→  const response_length = response.length;
276→
277→  const preview = buildResponsePreview(response);
278→
279→  const jsonPayload = extractJsonPayload(response);
280→  if (!jsonPayload) {
281→    console.error('No JSON found in analysis response');
282→    return {
283→      success: false,
284→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
285→    };
286→  }
287→
288→  let parsed: AnalysisResponse;
289→  try {
290→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
291→  } catch {
292→    // Attempt repair — handles trailing commas, unclosed braces, truncated output
293→    try {
294→      parsed = JSON.parse(jsonrepair(jsonPayload)) as AnalysisResponse;
295→    } catch (err) {
296→      const msg = err instanceof Error ? err.message : String(err);
297→      console.error('Failed to parse analysis response (after jsonrepair):', err);
298→      return {
299→        success: false,
300→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
301→      };
302→    }
303→  }
304→
305→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
306→    console.error('Invalid analysis response structure');
307→    return {
308→      success: false,
309→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
310→    };
311→  }
312→
313→  parsed.decisions = parsed.decisions || [];
314→  parsed.learnings = parsed.learnings || [];
315→
316→  // Validate session_character — drop if not a recognized value
317→  if (parsed.session_character && !VALID_SESSION_CHARACTERS.has(parsed.session_character)) {
318→    parsed.session_character = undefined;
319→  }
320→
321→  return { success: true, data: parsed };
322→}
