454→export interface PromptQualityResponse {
455→  efficiencyScore: number;
456→  potentialMessageReduction: number;
457→  overallAssessment: string;
458→  wastedTurns: WastedTurn[];
459→  antiPatterns: AntiPattern[];
460→  sessionTraits: SessionTrait[];
461→  tips: string[];
462→}
