464→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
465→  const response_length = response.length;
466→
467→  const preview = buildResponsePreview(response);
468→
469→  const jsonPayload = extractJsonPayload(response);
470→  if (!jsonPayload) {
471→    console.error('No JSON found in prompt quality response');
472→    return {
473→      success: false,
474→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
475→    };
476→  }
477→
478→  let parsed: PromptQualityResponse;
479→  try {
480→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
481→  } catch {
482→    try {
483→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
484→    } catch (err) {
485→      const msg = err instanceof Error ? err.message : String(err);
486→      console.error('Failed to parse prompt quality response (after jsonrepair):', err);
487→      return {
488→        success: false,
489→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
490→      };
491→    }
492→  }
493→
494→  if (typeof parsed.efficiencyScore !== 'number') {
495→    console.error('Invalid prompt quality response: missing efficiencyScore');
496→    return {
497→      success: false,
498→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiencyScore field', response_length, response_preview: preview },
499→    };
500→  }
501→
502→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
503→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
504→  parsed.overallAssessment = parsed.overallAssessment || '';
505→  parsed.wastedTurns = parsed.wastedTurns || [];
506→  parsed.antiPatterns = parsed.antiPatterns || [];
507→  parsed.sessionTraits = parsed.sessionTraits || [];
508→  parsed.tips = parsed.tips || [];
509→
510→  return { success: true, data: parsed };
511→}
