349→/**
350→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
351→ */
352→export async function findRecurringInsights(
353→  insights: Array<{
354→    id: string;
355→    type: string;
356→    title: string;
357→    summary: string;
358→    project_name: string;
359→    session_id: string;
360→  }>
361→): Promise<RecurringInsightResult> {
362→  if (!isLLMConfigured()) {
363→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
364→  }
365→
366→  const candidates = insights
367→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
368→    .slice(0, 200);
369→
370→  if (candidates.length < 2) {
371→    return {
372→      success: false,
373→      groups: [],
374→      updatedCount: 0,
375→      error: 'Need at least 2 non-summary insights to find patterns.',
376→    };
377→  }
378→
379→  try {
380→    const client = createLLMClient();
381→
382→    const insightData = candidates.map(i => ({
383→      id: i.id,
384→      type: i.type === 'technique' ? 'learning' : i.type,
385→      title: i.title,
386→      summary: i.summary.slice(0, 150),
387→      projectName: i.project_name,
388→      sessionId: i.session_id,
389→    }));
390→
391→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
392→
393→RULES:
394→- Only group insights that are genuinely about the same concept/topic
395→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
396→- A group must have at least 2 insights
397→- An insight can only belong to one group
398→- Provide a brief "theme" describing what the group shares
399→- If no recurring patterns exist, return an empty groups array
400→
401→INSIGHTS:
402→${JSON.stringify(insightData, null, 2)}
403→
404→Respond with valid JSON only:
405→{
406→  "groups": [
407→    {
408→      "insightIds": ["insight_abc", "insight_def"],
409→      "theme": "Brief description of the shared concept"
410→    }
411→  ]
412→}`;
413→
414→    const response = await client.chat([
415→      {
416→        role: 'system',
417→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
418→      },
419→      { role: 'user', content: prompt },
420→    ]);
421→
422→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
423→    if (!jsonMatch) {
424→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
425→    }
426→
427→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
428→    const groups = parsed.groups || [];
429→
430→    const validIds = new Set(candidates.map(i => i.id));
431→    const validGroups = groups
432→      .map(g => ({
433→        ...g,
434→        insightIds: g.insightIds.filter(id => validIds.has(id)),
435→      }))
436→      .filter(g => g.insightIds.length >= 2);
437→
438→    if (validGroups.length === 0) {
439→      return {
440→        success: true,
441→        groups: [],
442→        updatedCount: 0,
443→        usage: response.usage
444→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
445→          : undefined,
446→      };
447→    }
448→
449→    // Build bidirectional links
450→    const linkMap = new Map<string, string[]>();
451→    for (const group of validGroups) {
452→      for (const id of group.insightIds) {
453→        const others = group.insightIds.filter(otherId => otherId !== id);
454→        const existing = linkMap.get(id) || [];
455→        linkMap.set(id, [...new Set([...existing, ...others])]);
456→      }
457→    }
458→
459→    // Write links to SQLite
460→    const db = getDb();
461→    const updateLinks = db.prepare(
462→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
463→    );
464→
465→    for (const [insightId, linkedIds] of linkMap.entries()) {
466→      updateLinks.run(JSON.stringify(linkedIds), insightId);
467→    }
468→
469→    return {
470→      success: true,
471→      groups: validGroups,
472→      updatedCount: linkMap.size,
473→      usage: response.usage
474→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
475→        : undefined,
476→    };
477→  } catch (error) {
478→    return {
479→      success: false,
480→      groups: [],
481→      updatedCount: 0,
482→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
483→    };
484→  }
485→}
