487→// --- Internal helpers ---
488→
489→function chunkMessages(
490→  messages: SQLiteMessageRow[],
491→  estimateTokens: (text: string) => number
492→): SQLiteMessageRow[][] {
493→  const chunks: SQLiteMessageRow[][] = [];
494→  let currentChunk: SQLiteMessageRow[] = [];
495→  let currentTokens = 0;
496→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
497→
498→  for (const message of messages) {
499→    let toolResults: Array<{ output?: string }> = [];
500→    try {
501→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
502→    } catch {
503→      toolResults = [];
504→    }
505→
506→    const messageText = [
507→      message.content,
508→      message.thinking?.slice(0, 1000) ?? '',
509→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
510→    ].join(' ');
511→    const messageTokens = estimateTokens(messageText);
512→
513→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
514→      chunks.push(currentChunk);
515→      currentChunk = [];
516→      currentTokens = 0;
517→    }
518→
519→    currentChunk.push(message);
520→    currentTokens += messageTokens;
521→  }
522→
523→  if (currentChunk.length > 0) {
524→    chunks.push(currentChunk);
525→  }
526→
527→  return chunks;
528→}
