530→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
531→  if (responses.length === 0) {
532→    return {
533→      summary: { title: 'Analysis failed', content: '', bullets: [] },
534→      decisions: [],
535→      learnings: [],
536→    };
537→  }
538→
539→  if (responses.length === 1) return responses[0];
540→
541→  const merged: AnalysisResponse = {
542→    session_character: responses.find(r => r.session_character)?.session_character,
543→    summary: responses[0].summary,
544→    decisions: [],
545→    learnings: [],
546→  };
547→
548→  for (const response of responses) {
549→    merged.decisions.push(...response.decisions);
550→    merged.learnings.push(...response.learnings);
551→  }
552→
553→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
554→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
555→
556→  return merged;
557→}
558→
559→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
560→  const seen = new Set<string>();
561→  return items.filter((item) => {
562→    const normalized = item.title.toLowerCase().trim();
563→    if (seen.has(normalized)) return false;
564→    seen.add(normalized);
565→    return true;
566→  });
567→}
