569→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
570→  const insights: InsightRow[] = [];
571→  const now = new Date().toISOString();
572→
573→  insights.push({
574→    id: randomUUID(),
575→    session_id: session.id,
576→    project_id: session.project_id,
577→    project_name: session.project_name,
578→    type: 'summary',
579→    title: response.summary.title,
580→    content: response.summary.content,
581→    summary: response.summary.content,
582→    bullets: JSON.stringify(response.summary.bullets),
583→    confidence: 0.9,
584→    source: 'llm',
585→    metadata: response.summary.outcome
586→      ? JSON.stringify({ outcome: response.summary.outcome })
587→      : null,
588→    timestamp: session.ended_at,
589→    created_at: now,
590→    scope: 'session',
591→    analysis_version: ANALYSIS_VERSION,
592→  });
593→
594→  for (const decision of response.decisions) {
595→    const confidence = decision.confidence ?? 85;
596→    if (confidence < 70) continue;
597→
598→    const content = decision.situation && decision.choice
599→      ? `${decision.situation} → ${decision.choice}`
600→      : decision.choice || decision.situation || decision.title;
601→
602→    const altBullets = (decision.alternatives || [])
603→      .filter(a => a && typeof a === 'object' && a.option)
604→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
605→
606→    insights.push({
607→      id: randomUUID(),
608→      session_id: session.id,
609→      project_id: session.project_id,
610→      project_name: session.project_name,
611→      type: 'decision',
612→      title: decision.title,
613→      content,
614→      summary: (decision.choice || content).slice(0, 200),
615→      bullets: JSON.stringify(altBullets),
616→      confidence: confidence / 100,
617→      source: 'llm',
618→      metadata: JSON.stringify({
619→        situation: decision.situation,
620→        choice: decision.choice,
621→        reasoning: decision.reasoning,
622→        alternatives: decision.alternatives,
623→        trade_offs: decision.trade_offs,
624→        revisit_when: decision.revisit_when,
625→        evidence: decision.evidence,
626→      }),
627→      timestamp: session.ended_at,
628→      created_at: now,
629→      scope: 'session',
630→      analysis_version: ANALYSIS_VERSION,
631→    });
632→  }
633→
634→  for (const learning of response.learnings) {
635→    const confidence = learning.confidence ?? 80;
636→    if (confidence < 70) continue;
637→
638→    const content = learning.takeaway || learning.title;
639→
640→    insights.push({
641→      id: randomUUID(),
642→      session_id: session.id,
643→      project_id: session.project_id,
644→      project_name: session.project_name,
645→      type: 'learning',
646→      title: learning.title,
647→      content,
648→      summary: content.slice(0, 200),
649→      bullets: JSON.stringify([]),
650→      confidence: confidence / 100,
651→      source: 'llm',
652→      metadata: JSON.stringify({
653→        symptom: learning.symptom,
654→        root_cause: learning.root_cause,
655→        takeaway: learning.takeaway,
656→        applies_when: learning.applies_when,
657→        evidence: learning.evidence,
658→      }),
659→      timestamp: session.ended_at,
660→      created_at: now,
661→      scope: 'session',
662→      analysis_version: ANALYSIS_VERSION,
663→    });
664→  }
665→
666→  return insights;
667→}
