{
  "narrative": "Your 300-500 word analysis of the most significant patterns",
  "topFriction": [
    {
      "category": "category-name",
      "significance": "Why this matters",
      "rootCause": "Likely underlying cause",
      "trend": "increasing | stable | decreasing | new"
    }
  ],
  "topWins": [
    {
      "pattern": "Description of what works",
      "significance": "Why this is effective"
    }
  ]
}

Respond with valid JSON only, wrapped in <json>...</json> tags.\`;
}

// --- Rules & Skills ---

export const RULES_SKILLS_SYSTEM_PROMPT = \`You are generating actionable artifacts from cross-session analysis of a developer's AI coding sessions. You will receive recurring friction patterns and effective practices.

Your job is to produce concrete, copy-paste-ready artifacts:
1. CLAUDE.md rules — specific instructions to add to the AI assistant's config
2. Skill templates — reusable workflows for repetitive tasks
3. Hook configurations — automation triggers

RULES:
- Only generate artifacts for patterns with 3+ occurrences (friction) or 2+ occurrences (effective patterns)
- Rules must be specific enough to be actionable: "Always run tests before creating PRs" not "Be careful with code"
- Skill templates must include step-by-step instructions
- Hook configs must include the event trigger and command
- Max 5 rules, 3 skills, 3 hooks
- Each artifact must reference the friction pattern or effective practice it addresses

Respond with valid JSON only, wrapped in <json>...</json> tags.\`;

export function generateRulesSkillsPrompt(data: {
  recurringFriction: Array<{ category: string; count: number; avg_severity: number; examples: string[] }>;
  effectivePatterns: Array<{ description: string; frequency: number; avg_confidence: number }>;
  antiPatterns?: Array<{ name: string; count: number; examples: string[] }>;
  targetTool: string;
}): string {
  return \`Generate actionable artifacts from these recurring patterns.

TARGET TOOL: \${data.targetTool} (generate artifacts compatible with this tool's ecosystem)

RECURRING FRICTION (3+ occurrences):
\${JSON.stringify(data.recurringFriction, null, 2)}

EFFECTIVE PATTERNS (2+ occurrences):
\${JSON.stringify(data.effectivePatterns, null, 2)}

\${data.antiPatterns ? \`PROMPT ANTI-PATTERNS:\\n\${JSON.stringify(data.antiPatterns, null, 2)}\` : ''}

Respond with this JSON format:
{
  "claudeMdRules": [
    {
      "rule": "The exact text to add to CLAUDE.md",
      "rationale": "Why this rule helps (reference the friction pattern)",
      "frictionSource": "category-name (N occurrences)"
    }
  ],
  "skillTemplates": [
    {
      "name": "skill-name",
      "description": "What this skill automates",
      "content": "Full skill template content with steps"
    }
  ],
  "hookConfigs": [
    {
      "event": "pre-commit | post-file-edit | etc.",
      "command": "The shell command to run",
      "rationale": "Why this automation helps"
    }
  ]
}

Respond with valid JSON only, wrapped in <json>...</json> tags.\`;
}

// --- Working Style ---

export const WORKING_STYLE_SYSTEM_PROMPT = \`You are writing a brief working style profile based on aggregated statistics from a developer's AI coding sessions. You will receive distributions of workflow patterns, outcomes, session types, and friction frequency.

Your job is to describe WHAT you see, not what they should change. Write in second person ("You tend to...").

RULES:
- Base every statement on the statistics provided
- Keep the narrative to 3-5 sentences
- Be descriptive, not prescriptive (no advice)
- Mention the dominant workflow pattern, outcome distribution, and any notable characteristics
- If the data is too sparse (< 5 sessions), say so and keep it brief

Respond with valid JSON only, wrapped in <json>...</json> tags.\`;

export function generateWorkingStylePrompt(data: {
  workflowDistribution: Record<string, number>;
  outcomeDistribution: Record<string, number>;
  characterDistribution: Record<string, number>;
  totalSessions: number;
  period: string;
  frictionFrequency: number;
}): string {
  return \`Write a working style profile based on \${data.totalSessions} sessions over \${data.period}.

WORKFLOW PATTERNS:
\${JSON.stringify(data.workflowDistribution, null, 2)}

OUTCOME SATISFACTION:
\${JSON.stringify(data.outcomeDistribution, null, 2)}

SESSION TYPES:
\${JSON.stringify(data.characterDistribution, null, 2)}

FRICTION FREQUENCY: \${data.frictionFrequency} total friction points across all sessions

Respond with this JSON format:
{
  "narrative": "3-5 sentence working style description"
}

Respond with valid JSON only, wrapped in <json>...</json> tags.\`;
}
```

**CRITICAL:** Use template literals with `\${}` for interpolation throughout. The CANONICAL_FRICTION_CATEGORIES import is used but doesn't need to be interpolated into synthesis prompts — it's only needed in extraction prompts.

## Task 3.3: Create `server/src/routes/reflect.ts`

Create a new Hono router:

### POST /api/reflect/generate (SSE)
Body: `{ sections?: ReflectSection[], period?: string, project?: string, source?: string }`

This is the main generation pipeline:
1. Query facets from `session_facets` table
2. Aggregate in code (reuse the aggregation logic from facets/aggregated)
3. For each requested section, call the corresponding synthesis prompt
4. Stream progress and return results

### GET /api/reflect/results
Query params: project, period, source
Returns stored/cached reflect results (for now, just re-runs the aggregation queries — caching is a future optimization)

Implementation:

```typescript
import { Hono } from 'hono';
import { streamSSE } from 'hono/streaming';
import { getDb } from '@code-insights/cli/db/client';
import { jsonrepair } from 'jsonrepair';
import { createLLMClient, isLLMConfigured } from '../llm/client.js';
import { extractJsonPayload } from '../llm/prompts.js';
import {
  FRICTION_WINS_SYSTEM_PROMPT,
  generateFrictionWinsPrompt,
  RULES_SKILLS_SYSTEM_PROMPT,
  generateRulesSkillsPrompt,
  WORKING_STYLE_SYSTEM_PROMPT,
  generateWorkingStylePrompt,
} from '../llm/reflect-prompts.js';
import type { ReflectSection } from '@code-insights/cli/types';

const app = new Hono();

const ALL_SECTIONS: ReflectSection[] = ['friction-wins', 'rules-skills', 'working-style'];

function buildPeriodFilter(period: string): string | null {
  const now = new Date();
  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
  return null;
}

function buildWhereClause(period: string, project?: string, source?: string): { where: string; params: (string | number)[] } {
  const conditions: string[] = [];
  const params: (string | number)[] = [];

  const periodStart = buildPeriodFilter(period);
  if (periodStart) {
    conditions.push('s.started_at >= ?');
    params.push(periodStart);
  }
  if (project) {
    conditions.push('s.project_id = ?');
    params.push(project);
  }
  if (source) {
    conditions.push('s.source_tool = ?');
    params.push(source);
  }

  return {
    where: conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '',
    params,
  };
}

function getAggregatedData(db: ReturnType<typeof getDb>, where: string, params: (string | number)[]) {
  // Same aggregation queries as facets/aggregated
  const frictionCategories = db.prepare(`
    SELECT
      json_extract(je.value, '$.category') as category,
      COUNT(*) as count,
      AVG(CASE
        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
        ELSE 1
      END) as avg_severity,
      json_group_array(json_extract(je.value, '$.description')) as examples
    FROM session_facets sf
    JOIN sessions s ON sf.session_id = s.id
    CROSS JOIN json_each(sf.friction_points) je
    ${where}
    GROUP BY category
    ORDER BY count DESC, avg_severity DESC
  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string }>;

  const effectivePatterns = db.prepare(`
    SELECT
      json_extract(je.value, '$.description') as description,
      COUNT(*) as frequency,
      AVG(json_extract(je.value, '$.confidence')) as avg_confidence
    FROM session_facets sf
    JOIN sessions s ON sf.session_id = s.id
    CROSS JOIN json_each(sf.effective_patterns) je
    ${where}
    GROUP BY description
    ORDER BY frequency DESC, avg_confidence DESC
  `).all(...params) as Array<{ description: string; frequency: number; avg_confidence: number }>;

  const outcomeDistribution = db.prepare(`
    SELECT outcome_satisfaction, COUNT(*) as count
    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
    ${where} GROUP BY outcome_satisfaction
  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;

  const workflowDistribution = db.prepare(`
    SELECT workflow_pattern, COUNT(*) as count
    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
    ${where} AND sf.workflow_pattern IS NOT NULL GROUP BY workflow_pattern
  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;

  const characterDistribution = db.prepare(`
    SELECT session_character, COUNT(*) as count
    FROM sessions s ${where} AND s.session_character IS NOT NULL GROUP BY session_character
  `).all(...params) as Array<{ session_character: string; count: number }>;

  const totalRow = db.prepare(
    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
  ).get(...params) as { count: number };

  // Total friction points count
  const frictionTotal = frictionCategories.reduce((sum, fc) => sum + fc.count, 0);

  return {
    frictionCategories: frictionCategories.map(fc => ({
      ...fc,
      examples: JSON.parse(fc.examples) as string[],
    })),
    effectivePatterns,
    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
    totalSessions: totalRow.count,
    frictionTotal,
  };
}

function parseLLMJson<T>(response: string): T | null {
  const payload = extractJsonPayload(response);
  if (!payload) return null;
  try {
    return JSON.parse(payload) as T;
  } catch {
    try {
      return JSON.parse(jsonrepair(payload)) as T;
    } catch {
      return null;
    }
  }
}

// Auto-detect dominant source tool from database
function detectTargetTool(db: ReturnType<typeof getDb>): string {
  const row = db.prepare(
    `SELECT source_tool, COUNT(*) as count FROM sessions GROUP BY source_tool ORDER BY count DESC LIMIT 1`
  ).get() as { source_tool: string; count: number } | undefined;
  return row?.source_tool || 'claude-code';
}

// POST /api/reflect/generate — SSE endpoint for generating reflect sections
app.post('/generate', async (c) => {
  if (!isLLMConfigured()) {
    return c.json({ error: 'LLM not configured.' }, 400);
  }

  const body = await c.req.json<{
    sections?: ReflectSection[];
    period?: string;
    project?: string;
    source?: string;
  }>();

  const sections = body.sections && body.sections.length > 0 ? body.sections : ALL_SECTIONS;
  const period = body.period || '7d';

  const db = getDb();
  const { where, params } = buildWhereClause(period, body.project, body.source);

  return streamSSE(c, async (stream) => {
    const abortSignal = c.req.raw.signal;

    try {
      await stream.writeSSE({
        event: 'progress',
        data: JSON.stringify({ phase: 'aggregating', message: 'Aggregating facets...' }),
      });

      const aggregated = getAggregatedData(db, where, params);

      if (aggregated.totalSessions === 0) {
        await stream.writeSSE({
          event: 'error',
          data: JSON.stringify({ error: 'No sessions with facets found. Run analysis first.' }),
        });
        return;
      }

      const client = createLLMClient();
      const results: Record<string, unknown> = {};
      const targetTool = detectTargetTool(db);

      for (const section of sections) {
        if (abortSignal.aborted) break;

        await stream.writeSSE({
          event: 'progress',
          data: JSON.stringify({ phase: 'synthesizing', section, message: `Generating ${section}...` }),
        });

        if (section === 'friction-wins') {
          const prompt = generateFrictionWinsPrompt({
            frictionCategories: aggregated.frictionCategories,
            effectivePatterns: aggregated.effectivePatterns,
            totalSessions: aggregated.totalSessions,
            period,
          });
          const response = await client.chat([
            { role: 'system', content: FRICTION_WINS_SYSTEM_PROMPT },
            { role: 'user', content: prompt },
          ], { signal: abortSignal });
          const parsed = parseLLMJson(response.content);
          results['friction-wins'] = {
            section: 'friction-wins',
            ...parsed,
            frictionCategories: aggregated.frictionCategories,
            effectivePatterns: aggregated.effectivePatterns,
            generatedAt: new Date().toISOString(),
          };
        } else if (section === 'rules-skills') {
          const recurringFriction = aggregated.frictionCategories.filter(fc => fc.count >= 3);
          const recurringPatterns = aggregated.effectivePatterns.filter(ep => ep.frequency >= 2);
          const prompt = generateRulesSkillsPrompt({
            recurringFriction,
            effectivePatterns: recurringPatterns,
            targetTool,
          });
          const response = await client.chat([
            { role: 'system', content: RULES_SKILLS_SYSTEM_PROMPT },
            { role: 'user', content: prompt },
          ], { signal: abortSignal });
          const parsed = parseLLMJson(response.content);
          results['rules-skills'] = {
            section: 'rules-skills',
            ...parsed,
            targetTool,
            generatedAt: new Date().toISOString(),
          };
        } else if (section === 'working-style') {
          const prompt = generateWorkingStylePrompt({
            workflowDistribution: aggregated.workflowDistribution,
            outcomeDistribution: aggregated.outcomeDistribution,
            characterDistribution: aggregated.characterDistribution,
            totalSessions: aggregated.totalSessions,
            period,
            frictionFrequency: aggregated.frictionTotal,
          });
          const response = await client.chat([
            { role: 'system', content: WORKING_STYLE_SYSTEM_PROMPT },
            { role: 'user', content: prompt },
          ], { signal: abortSignal });
          const parsed = parseLLMJson(response.content);
          results['working-style'] = {
            section: 'working-style',
            ...parsed,
            workflowDistribution: aggregated.workflowDistribution,
            outcomeDistribution: aggregated.outcomeDistribution,
            characterDistribution: aggregated.characterDistribution,
            generatedAt: new Date().toISOString(),
          };
        }
      }

      await stream.writeSSE({
        event: 'complete',
        data: JSON.stringify({ results }),
      });
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      await stream.writeSSE({
        event: 'error',
        data: JSON.stringify({ error: message }),
      }).catch(() => {});
    }
  });
});

// GET /api/reflect/results — returns aggregated data (no LLM call)
// For now, returns raw aggregated facet data; synthesis results require /generate
app.get('/results', (c) => {
  const db = getDb();
  const period = c.req.query('period') || '7d';
  const project = c.req.query('project');
  const source = c.req.query('source');

  const { where, params } = buildWhereClause(period, project, source);
  const aggregated = getAggregatedData(db, where, params);

  return c.json(aggregated);
});

export default app;
```

