399→/**
400→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
401→ */
402→export async function findRecurringInsights(
403→  insights: Array<{
404→    id: string;
405→    type: string;
406→    title: string;
407→    summary: string;
408→    project_name: string;
409→    session_id: string;
410→  }>
411→): Promise<RecurringInsightResult> {
412→  if (!isLLMConfigured()) {
413→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
414→  }
415→
416→  const candidates = insights
417→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
418→    .slice(0, 200);
419→
420→  if (candidates.length < 2) {
421→    return {
422→      success: false,
423→      groups: [],
424→      updatedCount: 0,
425→      error: 'Need at least 2 non-summary insights to find patterns.',
426→    };
427→  }
428→
429→  try {
430→    const client = createLLMClient();
431→
432→    const insightData = candidates.map(i => ({
433→      id: i.id,
434→      type: i.type === 'technique' ? 'learning' : i.type,
435→      title: i.title,
436→      summary: i.summary.slice(0, 150),
437→      projectName: i.project_name,
438→      sessionId: i.session_id,
439→    }));
440→
441→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
442→
443→RULES:
444→- Only group insights that are genuinely about the same concept/topic
445→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
446→- A group must have at least 2 insights
447→- An insight can only belong to one group
448→- Provide a brief "theme" describing what the group shares
449→- If no recurring patterns exist, return an empty groups array
450→
451→INSIGHTS:
452→${JSON.stringify(insightData, null, 2)}
453→
454→Respond with valid JSON only:
455→{
456→  "groups": [
457→    {
458→      "insightIds": ["insight_abc", "insight_def"],
459→      "theme": "Brief description of the shared concept"
460→    }
461→  ]
462→}`;
463→
464→    const response = await client.chat([
465→      {
466→        role: 'system',
467→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
468→      },
469→      { role: 'user', content: prompt },
470→    ]);
471→
472→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
473→    if (!jsonMatch) {
474→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
475→    }
476→
477→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
478→    const groups = parsed.groups || [];
479→
480→    const validIds = new Set(candidates.map(i => i.id));
481→    const validGroups = groups
482→      .map(g => ({
483→        ...g,
484→        insightIds: g.insightIds.filter(id => validIds.has(id)),
485→      }))
486→      .filter(g => g.insightIds.length >= 2);
487→
488→    if (validGroups.length === 0) {
489→      return {
490→        success: true,
491→        groups: [],
492→        updatedCount: 0,
493→        usage: response.usage
494→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
495→          : undefined,
496→      };
497→    }
498→
499→    // Build bidirectional links
500→    const linkMap = new Map<string, string[]>();
501→    for (const group of validGroups) {
502→      for (const id of group.insightIds) {
503→        const others = group.insightIds.filter(otherId => otherId !== id);
504→        const existing = linkMap.get(id) || [];
505→        linkMap.set(id, [...new Set([...existing, ...others])]);
506→      }
507→    }
508→
509→    // Write links to SQLite
510→    const db = getDb();
511→    const updateLinks = db.prepare(
512→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
513→    );
514→
515→    for (const [insightId, linkedIds] of linkMap.entries()) {
516→      updateLinks.run(JSON.stringify(linkedIds), insightId);
517→    }
518→
519→    return {
520→      success: true,
521→      groups: validGroups,
522→      updatedCount: linkMap.size,
523→      usage: response.usage
524→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
525→        : undefined,
526→    };
527→  } catch (error) {
528→    return {
529→      success: false,
530→      groups: [],
531→      updatedCount: 0,
532→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
533→    };
534→  }
535→}
536→
537→// --- Internal helpers ---
538→
539→function chunkMessages(
540→  messages: SQLiteMessageRow[],
541→  estimateTokens: (text: string) => number
542→): SQLiteMessageRow[][] {
543→  const chunks: SQLiteMessageRow[][] = [];
544→  let currentChunk: SQLiteMessageRow[] = [];
545→  let currentTokens = 0;
546→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
547→
548→  for (const message of messages) {
549→    let toolResults: Array<{ output?: string }> = [];
550→    try {
551→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
552→    } catch {
553→      toolResults = [];
554→    }
555→
556→    const messageText = [
557→      message.content,
558→      message.thinking?.slice(0, 1000) ?? '',
559→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
560→    ].join(' ');
561→    const messageTokens = estimateTokens(messageText);
562→
563→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
564→      chunks.push(currentChunk);
565→      currentChunk = [];
566→      currentTokens = 0;
567→    }
568→
569→    currentChunk.push(message);
570→    currentTokens += messageTokens;
571→  }
572→
573→  if (currentChunk.length > 0) {
574→    chunks.push(currentChunk);
575→  }
576→
577→  return chunks;
578→}
579→
580→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
581→  if (responses.length === 0) {
582→    return {
583→      summary: { title: 'Analysis failed', content: '', bullets: [] },
584→      decisions: [],
585→      learnings: [],
586→    };
587→  }
588→
589→  if (responses.length === 1) return responses[0];
590→
591→  const merged: AnalysisResponse = {
592→    session_character: responses.find(r => r.session_character)?.session_character,
593→    summary: responses[0].summary,
594→    decisions: [],
595→    learnings: [],
596→  };
597→
598→  for (const response of responses) {
599→    merged.decisions.push(...response.decisions);
600→    merged.learnings.push(...response.learnings);
601→  }
602→
603→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
604→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
605→
606→  return merged;
607→}
608→
609→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
610→  const seen = new Set<string>();
611→  return items.filter((item) => {
612→    const normalized = item.title.toLowerCase().trim();
613→    if (seen.has(normalized)) return false;
614→    seen.add(normalized);
615→    return true;
616→  });
617→}
618→
619→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
620→  const insights: InsightRow[] = [];
621→  const now = new Date().toISOString();
622→
623→  insights.push({
624→    id: randomUUID(),
625→    session_id: session.id,
626→    project_id: session.project_id,
627→    project_name: session.project_name,
628→    type: 'summary',
629→    title: response.summary.title,
630→    content: response.summary.content,
631→    summary: response.summary.content,
632→    bullets: JSON.stringify(response.summary.bullets),
633→    confidence: 0.9,
634→    source: 'llm',
635→    metadata: response.summary.outcome
636→      ? JSON.stringify({ outcome: response.summary.outcome })
637→      : null,
638→    timestamp: session.ended_at,
639→    created_at: now,
640→    scope: 'session',
641→    analysis_version: ANALYSIS_VERSION,
642→  });
643→
644→  for (const decision of response.decisions) {
645→    const confidence = decision.confidence ?? 85;
646→    if (confidence < 70) continue;
647→
648→    const content = decision.situation && decision.choice
649→      ? `${decision.situation} → ${decision.choice}`
650→      : decision.choice || decision.situation || decision.title;
651→
652→    const altBullets = (decision.alternatives || [])
653→      .filter(a => a && typeof a === 'object' && a.option)
654→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
655→
656→    insights.push({
657→      id: randomUUID(),
658→      session_id: session.id,
659→      project_id: session.project_id,
660→      project_name: session.project_name,
661→      type: 'decision',
662→      title: decision.title,
663→      content,
664→      summary: (decision.choice || content).slice(0, 200),
665→      bullets: JSON.stringify(altBullets),
666→      confidence: confidence / 100,
667→      source: 'llm',
668→      metadata: JSON.stringify({
669→        situation: decision.situation,
670→        choice: decision.choice,
671→        reasoning: decision.reasoning,
672→        alternatives: decision.alternatives,
673→        trade_offs: decision.trade_offs,
674→        revisit_when: decision.revisit_when,
675→        evidence: decision.evidence,
676→      }),
677→      timestamp: session.ended_at,
678→      created_at: now,
679→      scope: 'session',
680→      analysis_version: ANALYSIS_VERSION,
681→    });
682→  }
683→
684→  for (const learning of response.learnings) {
685→    const confidence = learning.confidence ?? 80;
686→    if (confidence < 70) continue;
687→
688→    const content = learning.takeaway || learning.title;
689→
690→    insights.push({
691→      id: randomUUID(),
692→      session_id: session.id,
693→      project_id: session.project_id,
694→      project_name: session.project_name,
695→      type: 'learning',
696→      title: learning.title,
697→      content,
698→      summary: content.slice(0, 200),
699→      bullets: JSON.stringify([]),
700→      confidence: confidence / 100,
701→      source: 'llm',
702→      metadata: JSON.stringify({
703→        symptom: learning.symptom,
704→        root_cause: learning.root_cause,
705→        takeaway: learning.takeaway,
706→        applies_when: learning.applies_when,
707→        evidence: learning.evidence,
708→      }),
709→      timestamp: session.ended_at,
710→      created_at: now,
711→      scope: 'session',
712→      analysis_version: ANALYSIS_VERSION,
713→    });
714→  }
715→
716→  return insights;
717→}
718→
719→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
720→  const now = new Date().toISOString();
721→
722→  return {
723→    id: randomUUID(),
