787→interface DeleteOptions {
788→  excludeTypes?: string[];
789→  includeOnlyTypes?: string[];
790→  excludeIds?: string[];
791→}
792→
793→/**
794→ * Delete insights for a session, with optional type and ID exclusions.
795→ */
796→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
797→  const db = getDb();
798→  const conditions: string[] = ['session_id = ?'];
799→  const params: (string | number)[] = [sessionId];
800→
801→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
802→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
803→    params.push(...opts.excludeTypes);
804→  }
805→
806→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
807→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
808→    params.push(...opts.includeOnlyTypes);
809→  }
810→
811→  if (opts.excludeIds && opts.excludeIds.length > 0) {
812→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
813→    params.push(...opts.excludeIds);
814→  }
815→
816→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
817→}
