886→    try {
887→      facets = JSON.parse(jsonPayload);
888→    } catch {
889→      facets = JSON.parse(jsonrepair(jsonPayload));
890→    }
891→
892→    if (facets) {
893→      saveFacetsToDb(session.id, facets, ANALYSIS_VERSION);
894→    }
895→
896→    return { success: true };
897→  } catch (error) {
898→    if (error instanceof Error && error.name === 'AbortError') {
899→      return { success: false, error: 'Cancelled' };
900→    }
901→    return {
902→      success: false,
903→      error: error instanceof Error ? error.message : 'Facet extraction failed',
904→    };
905→  }
906→}
