170→// ── Export ────────────────────────────────────────────────────────────────────
171→
172→export async function exportMarkdown(body: {
173→  sessionIds?: string[];
174→  projectId?: string;
175→  template?: ExportTemplate;
176→}): Promise<string> {
177→  const res = await fetch(`${BASE}/export/markdown`, {
178→    method: 'POST',
179→    headers: { 'Content-Type': 'application/json' },
180→    body: JSON.stringify(body),
181→  });
182→  if (!res.ok) {
183→    const text = await res.text().catch(() => res.statusText);
184→    throw new Error(`Export failed ${res.status}: ${text}`);
185→  }
186→  return res.text();
187→}
188→
189→// ── LLM Export Generate ───────────────────────────────────────────────────────
190→
191→export type ExportGenerateFormat = 'agent-rules' | 'knowledge-brief' | 'obsidian' | 'notion';
192→export type ExportGenerateScope = 'project' | 'all';
193→export type ExportGenerateDepth = 'essential' | 'standard' | 'comprehensive';
194→
195→export interface ExportGenerateRequest {
196→  scope: ExportGenerateScope;
197→  projectId?: string;
