import { Command } from 'commander';
import ora from 'ora';
import chalk from 'chalk';
import { loadConfig } from '../utils/config.js';

async function fetchWithSSE(url: string, body: Record<string, unknown>, signal?: AbortSignal): Promise<Record<string, unknown>> {
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
    signal,
  });

  if (!res.ok) {
    const text = await res.text().catch(() => res.statusText);
    throw new Error(`Server error ${res.status}: ${text}`);
  }

  if (!res.body) throw new Error('No response body');

  const reader = res.body.pipeThrough(new TextDecoderStream()).getReader();
  let buffer = '';
  let currentEvent = '';
  let currentData = '';
  let result: Record<string, unknown> = {};

  const spinner = ora({ text: 'Starting...', indent: 2 }).start();

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += value;
      const lines = buffer.split('\n');
      buffer = lines.pop() ?? '';

      for (const line of lines) {
        if (line.startsWith('event: ')) {
          currentEvent = line.slice(7).trim();
        } else if (line.startsWith('data: ')) {
          currentData = line.slice(6);
        } else if (line === '' && currentEvent && currentData) {
          const data = JSON.parse(currentData) as Record<string, unknown>;

          if (currentEvent === 'progress') {
            spinner.text = (data.message as string) || 'Processing...';
          } else if (currentEvent === 'complete') {
            spinner.succeed('Analysis complete');
            result = data;
          } else if (currentEvent === 'error') {
            spinner.fail((data.error as string) || 'Generation failed');
          }

          currentEvent = '';
          currentData = '';
        }
      }
    }
  } finally {
    reader.releaseLock();
  }

  return result;
}

async function reflectAction(options: {
  section?: string;
  period?: string;
  project?: string;
}): Promise<void> {
  const config = loadConfig();
  const port = config?.dashboard?.port || 7890;
  const baseUrl = `http://localhost:${port}`;

  // Check if server is running
  try {
    await fetch(`${baseUrl}/api/health`);
  } catch {
    console.log(chalk.yellow('  Dashboard server is not running.'));
    console.log(chalk.dim('  Start it with: code-insights dashboard'));
    console.log();
    process.exit(1);
  }

  const body: Record<string, unknown> = {
    period: options.period || '30d',
  };
  if (options.section) {
    body.sections = [options.section];
  }
  if (options.project) {
    body.project = options.project;
  }

  console.log();
  const data = await fetchWithSSE(`${baseUrl}/api/reflect/generate`, body);

  // Display results summary
  const results = data.results as Record<string, Record<string, unknown>> | undefined;
  if (!results) {
    console.log(chalk.dim('  No results generated.'));
    return;
  }

  console.log();

  // Friction & Wins summary
  const frictionWins = results['friction-wins'];
  if (frictionWins) {
    console.log(chalk.bold('  Friction & Wins'));
    if (frictionWins.narrative) {
      const lines = String(frictionWins.narrative).split('\n');
      for (const line of lines) {
        console.log(chalk.dim('  ') + line);
      }
    }
    console.log();
  }

  // Rules & Skills summary
  const rulesSkills = results['rules-skills'];
  if (rulesSkills) {
    console.log(chalk.bold('  Rules & Skills'));
    const rules = rulesSkills.claudeMdRules as Array<{ rule: string }> | undefined;
    if (rules && rules.length > 0) {
      console.log(chalk.dim('  CLAUDE.md rules:'));
      for (const r of rules) {
        console.log(`    ${chalk.cyan('→')} ${r.rule}`);
      }
    }
    const skills = rulesSkills.skillTemplates as Array<{ name: string }> | undefined;
    if (skills && skills.length > 0) {
      console.log(chalk.dim('  Skills:'));
      for (const s of skills) {
        console.log(`    ${chalk.cyan('→')} ${s.name}`);
      }
    }
    const hooks = rulesSkills.hookConfigs as Array<{ event: string; command: string }> | undefined;
    if (hooks && hooks.length > 0) {
      console.log(chalk.dim('  Hooks:'));
      for (const h of hooks) {
        console.log(`    ${chalk.cyan('→')} ${h.event}: ${h.command}`);
      }
    }
    console.log();
  }

  // Working Style summary
  const workingStyle = results['working-style'];
  if (workingStyle) {
    console.log(chalk.bold('  Working Style'));
    if (workingStyle.narrative) {
      const lines = String(workingStyle.narrative).split('\n');
      for (const line of lines) {
        console.log(chalk.dim('  ') + line);
      }
    }
    console.log();
  }

  console.log(chalk.dim('  View full results: code-insights dashboard → Patterns'));
  console.log();
}

export const reflectCommand = new Command('reflect')
  .description('Generate cross-session analysis (friction, rules, working style)')
  .option('--section <name>', 'Generate specific section: friction-wins, rules-skills, working-style')
  .option('-p, --period <period>', 'Time range: 7d, 30d, 90d, all', '30d')
  .option('--project <name>', 'Scope to a single project')
  .action(reflectAction);

// ──────────────────────────────────────────────────────
// stats patterns — View cross-session pattern analysis
// ──────────────────────────────────────────────────────

import chalk from 'chalk';
import ora from 'ora';
import type { StatsFlags } from '../data/types.js';
import { resolveDataSource } from '../data/source.js';
import { handleStatsError } from './error-handler.js';
import { loadConfig } from '../../../utils/config.js';
import { sectionHeader } from '../render/layout.js';

interface AggregatedData {
  frictionCategories: Array<{
    category: string;
    count: number;
    avg_severity: number;
    examples: string[];
  }>;
  effectivePatterns: Array<{
    description: string;
    frequency: number;
    avg_confidence: number;
  }>;
  outcomeDistribution: Record<string, number>;
  workflowDistribution: Record<string, number>;
  characterDistribution: Record<string, number>;
  totalSessions: number;
  frictionTotal: number;
}

export async function patternsAction(flags: StatsFlags): Promise<void> {
  try {
    const source = await resolveDataSource(flags);

    // Sync first unless --no-sync
    if (!flags.noSync) {
      const spinner = ora({ text: 'Syncing...', indent: 2 }).start();
      try {
        const prepResult = await source.prepare(flags);
        spinner.succeed(prepResult.message);
      } catch {
        spinner.warn('Sync failed (showing cached data)');
      }
    }

    const config = loadConfig();
    const port = config?.dashboard?.port || 7890;
    const baseUrl = `http://localhost:${port}`;

    // Check if server is running
    try {
      await fetch(`${baseUrl}/api/health`);
    } catch {
      console.log();
      console.log(chalk.yellow('  Dashboard server is not running.'));
      console.log(chalk.dim('  Start it with: code-insights dashboard'));
      console.log();
      return;
    }

    // Fetch aggregated data
    const params = new URLSearchParams();
    params.set('period', flags.period);
    if (flags.project) params.set('project', flags.project);
    if (flags.source) params.set('source', flags.source);

    const res = await fetch(`${baseUrl}/api/reflect/results?${params.toString()}`);
    if (!res.ok) {
      console.log(chalk.red(`  Failed to fetch patterns: ${res.statusText}`));
      return;
    }

    const data = await res.json() as AggregatedData;

    if (data.totalSessions === 0) {
      console.log();
      console.log(chalk.dim('  No sessions with facets found.'));
      console.log(chalk.dim('  Run session analysis to extract facets, then try again.'));
      console.log();
      return;
    }

    console.log();
    console.log(sectionHeader(`Patterns (${flags.period}) — ${data.totalSessions} sessions`));
    console.log();

    // Friction categories
    if (data.frictionCategories.length > 0) {
      console.log(chalk.bold('  Friction Categories'));
      const maxCount = Math.max(...data.frictionCategories.map(fc => fc.count));
      for (const fc of data.frictionCategories.slice(0, 10)) {
        const barLen = Math.max(1, Math.round((fc.count / maxCount) * 20));
        const bar = '█'.repeat(barLen);
        const severityColor = fc.avg_severity >= 2.5 ? chalk.red : fc.avg_severity >= 1.5 ? chalk.yellow : chalk.green;
        console.log(`    ${chalk.dim(String(fc.count).padStart(3))} ${severityColor(bar)} ${fc.category}`);
      }
      console.log();
    }

    // Effective patterns
    if (data.effectivePatterns.length > 0) {
      console.log(chalk.bold('  Effective Patterns'));
      for (const ep of data.effectivePatterns.slice(0, 5)) {
        console.log(`    ${chalk.green('✓')} ${ep.description} ${chalk.dim(`(${ep.frequency}x)`)}`);
      }
      console.log();
    }

    // Outcome distribution
    const outcomes = Object.entries(data.outcomeDistribution);
    if (outcomes.length > 0) {
      console.log(chalk.bold('  Outcome Distribution'));
      for (const [outcome, count] of outcomes) {
        const icon = outcome === 'high' ? chalk.green('●') : outcome === 'medium' ? chalk.yellow('●') : outcome === 'low' ? chalk.red('●') : chalk.dim('●');
        console.log(`    ${icon} ${outcome}: ${count}`);
      }
      console.log();
    }

    // Workflow patterns
    const workflows = Object.entries(data.workflowDistribution);
    if (workflows.length > 0) {
      console.log(chalk.bold('  Workflow Patterns'));
      for (const [pattern, count] of workflows) {
        console.log(`    ${chalk.cyan('→')} ${pattern}: ${count}`);
      }
      console.log();
    }

    console.log(chalk.dim('  Generate full analysis: code-insights reflect'));
    console.log(chalk.dim('  View in dashboard: code-insights dashboard → Patterns'));
    console.log();
  } catch (error) {
    handleStatsError(error);
  }
}

