326→export interface ParseError {
327→  error_type: 'json_parse_error' | 'no_json_found' | 'invalid_structure';
328→  error_message: string;
329→  response_length: number;
330→  response_preview: string;
331→}
332→
333→function buildResponsePreview(text: string, head = 200, tail = 200): string {
334→  if (text.length <= head + tail + 20) return text;
335→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
336→}
337→
338→export type ParseResult<T> =
339→  | { success: true; data: T }
340→  | { success: false; error: ParseError };
341→
342→export function extractJsonPayload(response: string): string | null {
343→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
344→  if (tagged?.[1]) return tagged[1].trim();
345→  const jsonMatch = response.match(/\{[\s\S]*\}/);
346→  return jsonMatch ? jsonMatch[0] : null;
347→}
348→
349→/**
350→ * Parse the LLM response into structured insights.
351→ */
352→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
353→  const response_length = response.length;
354→
355→  const preview = buildResponsePreview(response);
356→
357→  const jsonPayload = extractJsonPayload(response);
358→  if (!jsonPayload) {
359→    console.error('No JSON found in analysis response');
360→    return {
361→      success: false,
362→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
363→    };
364→  }
365→
366→  let parsed: AnalysisResponse;
367→  try {
368→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
369→  } catch {
370→    // Attempt repair — handles trailing commas, unclosed braces, truncated output
371→    try {
372→      parsed = JSON.parse(jsonrepair(jsonPayload)) as AnalysisResponse;
373→    } catch (err) {
374→      const msg = err instanceof Error ? err.message : String(err);
375→      console.error('Failed to parse analysis response (after jsonrepair):', err);
376→      return {
377→        success: false,
378→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
379→      };
380→    }
381→  }
382→
383→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
384→    console.error('Invalid analysis response structure');
385→    return {
386→      success: false,
387→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
388→    };
389→  }
390→
391→  parsed.decisions = parsed.decisions || [];
392→  parsed.learnings = parsed.learnings || [];
393→  parsed.facets = parsed.facets || undefined;
394→
395→  // Validate session_character — drop if not a recognized value
396→  if (parsed.session_character && !VALID_SESSION_CHARACTERS.has(parsed.session_character)) {
397→    parsed.session_character = undefined;
398→  }
399→
400→  return { success: true, data: parsed };
401→}
