546→Session trait definitions:
547→- **context_drift**: Session covers too many unrelated objectives, causing the AI to lose context and produce lower quality output
548→- **objective_bloat**: Too many different tasks crammed into one session instead of focused, single-purpose sessions
549→- **late_context**: Critical requirements, constraints, or context provided late in the conversation that should have been mentioned upfront — causing rework or wasted turns
550→- **no_planning**: User jumped straight into implementation without discussing approach, requirements, or plan — leading to course corrections mid-session
551→- **good_structure**: Session was well-structured with clear objectives, upfront context, and logical flow (only include this if truly exemplary)
552→
553→Rules:
554→- messageIndex refers to the 0-based index of the USER message, as labeled in the conversation (e.g., User#0)
555→- Only include genuinely wasted turns, not normal back-and-forth
556→- Tips should be specific and actionable, not generic; include the relevant user message index in parentheses
557→- If the user prompted well, say so — don't manufacture issues
558→- potentialMessageReduction is how many fewer messages the session could have taken with better prompts
559→
560→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
561→}
562→
563→export interface WastedTurn {
564→  messageIndex: number;
565→  originalMessage?: string;
566→  whatWentWrong?: string;
567→  suggestedRewrite: string;
568→  turnsWasted?: number;
569→}
570→
571→export interface AntiPattern {
572→  name: string;
573→  description?: string;
574→  count: number;
575→  examples: string[];
576→  fix?: string;
577→}
578→
579→export interface SessionTrait {
580→  trait: 'context_drift' | 'objective_bloat' | 'late_context' | 'no_planning' | 'good_structure';
581→  severity: 'high' | 'medium' | 'low';
582→  description: string;
583→  evidence?: string;
584→  suggestion?: string;
585→}
586→
587→export interface PromptQualityResponse {
588→  efficiencyScore: number;
589→  potentialMessageReduction: number;
590→  overallAssessment: string;
591→  wastedTurns: WastedTurn[];
592→  antiPatterns: AntiPattern[];
593→  sessionTraits: SessionTrait[];
594→  tips: string[];
595→}
596→
597→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
598→  const response_length = response.length;
599→
600→  const preview = buildResponsePreview(response);
601→
602→  const jsonPayload = extractJsonPayload(response);
603→  if (!jsonPayload) {
604→    console.error('No JSON found in prompt quality response');
605→    return {
606→      success: false,
607→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
608→    };
609→  }
610→
611→  let parsed: PromptQualityResponse;
612→  try {
613→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
614→  } catch {
615→    try {
616→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
617→    } catch (err) {
618→      const msg = err instanceof Error ? err.message : String(err);
619→      console.error('Failed to parse prompt quality response (after jsonrepair):', err);
620→      return {
621→        success: false,
622→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
623→      };
624→    }
625→  }
626→
627→  if (typeof parsed.efficiencyScore !== 'number') {
628→    console.error('Invalid prompt quality response: missing efficiencyScore');
629→    return {
630→      success: false,
631→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiencyScore field', response_length, response_preview: preview },
632→    };
633→  }
634→
635→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
636→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
637→  parsed.overallAssessment = parsed.overallAssessment || '';
638→  parsed.wastedTurns = parsed.wastedTurns || [];
639→  parsed.antiPatterns = parsed.antiPatterns || [];
640→  parsed.sessionTraits = parsed.sessionTraits || [];
641→  parsed.tips = parsed.tips || [];
642→
643→  return { success: true, data: parsed };
644→}
