  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { isLLMConfigured } from '../llm/client.js';
  5→import { extractFacetsOnly } from '../llm/analysis.js';
  6→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  7→
  8→const app = new Hono();
  9→
 10→interface FacetRow {
 11→  session_id: string;
 12→  outcome_satisfaction: string;
 13→  workflow_pattern: string | null;
 14→  had_course_correction: number;
 15→  course_correction_reason: string | null;
 16→  iteration_count: number;
 17→  friction_points: string;     // JSON
 18→  effective_patterns: string;  // JSON
 19→  extracted_at: string;
 20→  analysis_version: string;
 21→}
 22→
 23→function buildPeriodFilter(period: string): string | null {
 24→  const now = new Date();
 25→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 26→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 27→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 28→  return null; // 'all'
 29→}
 30→
 31→// GET /api/facets
 32→// Query params: project (project_id), period (7d|30d|90d|all), source (source_tool filter)
 33→// Returns: { facets, missingCount, totalSessions }
 34→app.get('/', (c) => {
 35→  const db = getDb();
 36→  const project = c.req.query('project');
 37→  const period = c.req.query('period') || '7d';
 38→  const source = c.req.query('source');
 39→
 40→  const conditions: string[] = [];
 41→  const params: (string | number)[] = [];
 42→
 43→  const periodStart = buildPeriodFilter(period);
 44→  if (periodStart) {
 45→    conditions.push('s.started_at >= ?');
 46→    params.push(periodStart);
 47→  }
 48→  if (project) {
 49→    conditions.push('s.project_id = ?');
 50→    params.push(project);
 51→  }
 52→  if (source) {
 53→    conditions.push('s.source_tool = ?');
 54→    params.push(source);
 55→  }
 56→
 57→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
 58→
 59→  // Total sessions in scope
 60→  const totalRow = db.prepare(
 61→    `SELECT COUNT(*) as count FROM sessions s ${where}`
 62→  ).get(...params) as { count: number };
 63→
 64→  // Sessions with facets — join to sessions so period/project/source filters apply
 65→  const facets = db.prepare(
 66→    `SELECT sf.* FROM session_facets sf
 67→     JOIN sessions s ON sf.session_id = s.id
 68→     ${where}
 69→     ORDER BY s.started_at DESC`
 70→  ).all(...params) as FacetRow[];
 71→
 72→  return c.json({
 73→    facets,
 74→    missingCount: totalRow.count - facets.length,
 75→    totalSessions: totalRow.count,
 76→  });
 77→});
 78→
 79→// GET /api/facets/aggregated
 80→// Returns pre-aggregated friction categories and effective patterns for synthesis.
 81→// Uses json_each() to unpack JSON arrays stored in session_facets.friction_points
 82→// and session_facets.effective_patterns — aggregation done in SQL, not by LLM.
 83→app.get('/aggregated', (c) => {
 84→  const db = getDb();
 85→  const project = c.req.query('project');
 86→  const period = c.req.query('period') || '7d';
 87→  const source = c.req.query('source');
 88→
 89→  const conditions: string[] = [];
 90→  const params: (string | number)[] = [];
 91→
 92→  const periodStart = buildPeriodFilter(period);
 93→  if (periodStart) {
 94→    conditions.push('s.started_at >= ?');
 95→    params.push(periodStart);
 96→  }
 97→  if (project) {
 98→    conditions.push('s.project_id = ?');
 99→    params.push(project);
100→  }
101→  if (source) {
102→    conditions.push('s.source_tool = ?');
103→    params.push(source);
104→  }
105→
106→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
107→
108→  // Friction point aggregation using json_each to unpack the stored JSON array.
109→  // avg_severity maps text values to numeric weights (high=3, medium=2, low=1)
110→  // so we can rank categories by combined frequency × severity.
111→  const frictionCategories = db.prepare(`
112→    SELECT
113→      json_extract(je.value, '$.category') as category,
114→      COUNT(*) as count,
115→      AVG(CASE
116→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
117→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
118→        ELSE 1
119→      END) as avg_severity,
120→      json_group_array(json_extract(je.value, '$.description')) as examples
121→    FROM session_facets sf
122→    JOIN sessions s ON sf.session_id = s.id
123→    CROSS JOIN json_each(sf.friction_points) je
124→    ${where}
125→    GROUP BY category
126→    ORDER BY count DESC, avg_severity DESC
127→  `).all(...params) as Array<{
128→    category: string;
129→    count: number;
130→    avg_severity: number;
131→    examples: string;
132→  }>;
133→
134→  // Effective pattern aggregation — group identical descriptions across sessions
135→  const effectivePatterns = db.prepare(`
136→    SELECT
137→      json_extract(je.value, '$.description') as description,
138→      COUNT(*) as frequency,
139→      AVG(json_extract(je.value, '$.confidence')) as avg_confidence
140→    FROM session_facets sf
141→    JOIN sessions s ON sf.session_id = s.id
142→    CROSS JOIN json_each(sf.effective_patterns) je
143→    ${where}
144→    GROUP BY description
145→    ORDER BY frequency DESC, avg_confidence DESC
146→  `).all(...params) as Array<{
147→    description: string;
148→    frequency: number;
149→    avg_confidence: number;
150→  }>;
151→
152→  // Outcome distribution — indexed column, fast
153→  const outcomeDistribution = db.prepare(`
154→    SELECT outcome_satisfaction, COUNT(*) as count
155→    FROM session_facets sf
156→    JOIN sessions s ON sf.session_id = s.id
157→    ${where}
158→    GROUP BY outcome_satisfaction
159→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
160→
161→  // Workflow distribution — indexed column, fast; NULL rows excluded
162→  const workflowDistribution = db.prepare(`
163→    SELECT workflow_pattern, COUNT(*) as count
164→    FROM session_facets sf
165→    JOIN sessions s ON sf.session_id = s.id
166→    ${where}
167→    ${conditions.length > 0 ? 'AND' : 'WHERE'} sf.workflow_pattern IS NOT NULL
168→    GROUP BY workflow_pattern
169→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
170→
171→  // Session character from sessions table (not facets)
172→  const characterDistribution = db.prepare(`
173→    SELECT session_character, COUNT(*) as count
174→    FROM sessions s
175→    ${where}
176→    ${conditions.length > 0 ? 'AND' : 'WHERE'} s.session_character IS NOT NULL
177→    GROUP BY session_character
178→  `).all(...params) as Array<{ session_character: string; count: number }>;
179→
180→  // Parse examples from json_group_array output
181→  const parsedFriction = frictionCategories.map(fc => ({
182→    ...fc,
183→    examples: JSON.parse(fc.examples) as string[],
184→  }));
185→
186→  return c.json({
187→    frictionCategories: parsedFriction,
188→    effectivePatterns,
189→    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
190→    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
191→    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
192→  });
193→});
194→
195→// POST /api/facets/backfill
196→// Body: { sessionIds: string[] }
197→// Streams progress as facets are extracted one-by-one for sessions that lack them.
198→// Uses extractFacetsOnly (lightweight prompt: summary + first/last 20 messages).
199→app.post('/backfill', async (c) => {
200→  if (!isLLMConfigured()) {
201→    return c.json({ error: 'LLM not configured.' }, 400);
202→  }
203→
204→  const body = await c.req.json<{ sessionIds?: string[] }>();
205→  if (!body.sessionIds || !Array.isArray(body.sessionIds) || body.sessionIds.length === 0) {
206→    return c.json({ error: 'sessionIds array required' }, 400);
207→  }
208→
209→  const db = getDb();
210→
211→  return streamSSE(c, async (stream) => {
212→    const abortSignal = c.req.raw.signal;
213→    let completed = 0;
214→    let failed = 0;
215→    const total = body.sessionIds!.length;
216→
217→    for (const sessionId of body.sessionIds!) {
218→      if (abortSignal.aborted) break;
219→
220→      const session = db.prepare(
221→        `SELECT id, project_id, project_name, project_path, summary, ended_at
222→         FROM sessions WHERE id = ?`
223→      ).get(sessionId) as SessionData | undefined;
224→
225→      if (!session) {
226→        failed++;
227→        // Still emit progress so the client can track the count
228→        await stream.writeSSE({
229→          event: 'progress',
230→          data: JSON.stringify({
231→            completed,
232→            failed,
233→            total,
234→            currentSessionId: sessionId,
235→          }),
236→        });
237→        continue;
238→      }
239→
240→      const messages = db.prepare(
241→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
242→         FROM messages WHERE session_id = ? ORDER BY timestamp ASC`
243→      ).all(sessionId) as SQLiteMessageRow[];
244→
245→      const result = await extractFacetsOnly(session, messages, { signal: abortSignal });
246→      if (result.success) {
247→        completed++;
248→      } else {
249→        failed++;
250→      }
251→
252→      await stream.writeSSE({
253→        event: 'progress',
254→        data: JSON.stringify({
255→          completed,
256→          failed,
257→          total,
258→          currentSessionId: sessionId,
259→        }),
260→      });
261→    }
262→
263→    await stream.writeSSE({
264→      event: 'complete',
265→      data: JSON.stringify({ completed, failed, total }),
266→    });
267→  });
268→});
269→
270→export default app;
