  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { jsonrepair } from 'jsonrepair';
  5→import { createLLMClient, isLLMConfigured } from '../llm/client.js';
  6→import { extractJsonPayload } from '../llm/prompts.js';
  7→import {
  8→  FRICTION_WINS_SYSTEM_PROMPT,
  9→  generateFrictionWinsPrompt,
 10→  RULES_SKILLS_SYSTEM_PROMPT,
 11→  generateRulesSkillsPrompt,
 12→  WORKING_STYLE_SYSTEM_PROMPT,
 13→  generateWorkingStylePrompt,
 14→} from '../llm/reflect-prompts.js';
 15→import type { ReflectSection } from '@code-insights/cli/types';
 16→
 17→const app = new Hono();
 18→
 19→const ALL_SECTIONS: ReflectSection[] = ['friction-wins', 'rules-skills', 'working-style'];
 20→
 21→function buildPeriodFilter(period: string): string | null {
 22→  const now = new Date();
 23→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 24→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 25→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 26→  return null;
 27→}
 28→
 29→// Build WHERE clause from period/project/source filters.
 30→// Joins are against session_facets sf and sessions s (or just sessions s).
 31→// Returns WHERE clause string and params array.
 32→function buildWhereClause(
 33→  period: string,
 34→  project?: string,
 35→  source?: string
 36→): { where: string; params: (string | number)[] } {
 37→  const conditions: string[] = [];
 38→  const params: (string | number)[] = [];
 39→
 40→  const periodStart = buildPeriodFilter(period);
 41→  if (periodStart) {
 42→    conditions.push('s.started_at >= ?');
 43→    params.push(periodStart);
 44→  }
 45→  if (project) {
 46→    conditions.push('s.project_id = ?');
 47→    params.push(project);
 48→  }
 49→  if (source) {
 50→    conditions.push('s.source_tool = ?');
 51→    params.push(source);
 52→  }
 53→
 54→  return {
 55→    where: conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '',
 56→    params,
 57→  };
 58→}
 59→
 60→// Run all aggregation queries needed for synthesis.
 61→// Aggregation is done in code (SQL), not by LLM — LLMs synthesize, they don't count.
 62→function getAggregatedData(
 63→  db: ReturnType<typeof getDb>,
 64→  where: string,
 65→  params: (string | number)[]
 66→) {
 67→  // Determine whether to use WHERE or AND for additional predicates on non-join queries.
 68→  // The WHERE clause already handles session filters — additional predicates need AND.
 69→  const hasWhere = where.length > 0;
 70→  const extraPrefix = hasWhere ? 'AND' : 'WHERE';
 71→
 72→  const frictionCategories = db.prepare(`
 73→    SELECT
 74→      json_extract(je.value, '$.category') as category,
 75→      COUNT(*) as count,
 76→      AVG(CASE
 77→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
 78→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
 79→        ELSE 1
 80→      END) as avg_severity,
 81→      json_group_array(json_extract(je.value, '$.description')) as examples
 82→    FROM session_facets sf
 83→    JOIN sessions s ON sf.session_id = s.id
 84→    CROSS JOIN json_each(sf.friction_points) je
 85→    ${where}
 86→    GROUP BY category
 87→    ORDER BY count DESC, avg_severity DESC
 88→  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string }>;
 89→
 90→  const effectivePatterns = db.prepare(`
 91→    SELECT
 92→      json_extract(je.value, '$.description') as description,
 93→      COUNT(*) as frequency,
 94→      AVG(json_extract(je.value, '$.confidence')) as avg_confidence
 95→    FROM session_facets sf
 96→    JOIN sessions s ON sf.session_id = s.id
 97→    CROSS JOIN json_each(sf.effective_patterns) je
 98→    ${where}
 99→    GROUP BY description
100→    ORDER BY frequency DESC, avg_confidence DESC
101→  `).all(...params) as Array<{ description: string; frequency: number; avg_confidence: number }>;
102→
103→  const outcomeDistribution = db.prepare(`
104→    SELECT outcome_satisfaction, COUNT(*) as count
105→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
106→    ${where}
107→    GROUP BY outcome_satisfaction
108→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
109→
110→  // workflow_pattern can be NULL — filter those out for a clean distribution
111→  const workflowDistribution = db.prepare(`
112→    SELECT workflow_pattern, COUNT(*) as count
113→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
114→    ${where}
115→    ${extraPrefix} sf.workflow_pattern IS NOT NULL
116→    GROUP BY workflow_pattern
117→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
118→
119→  // session_character lives on the sessions table, not facets
120→  const characterDistribution = db.prepare(`
121→    SELECT session_character, COUNT(*) as count
122→    FROM sessions s
123→    ${where}
124→    ${extraPrefix} s.session_character IS NOT NULL
125→    GROUP BY session_character
126→  `).all(...params) as Array<{ session_character: string; count: number }>;
127→
128→  // Count faceted sessions (not all sessions — only those with extracted facets)
129→  const totalRow = db.prepare(
130→    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
131→  ).get(...params) as { count: number };
132→
133→  const frictionTotal = frictionCategories.reduce((sum, fc) => sum + fc.count, 0);
134→
135→  return {
136→    frictionCategories: frictionCategories.map(fc => ({
137→      ...fc,
138→      examples: JSON.parse(fc.examples) as string[],
139→    })),
140→    effectivePatterns,
141→    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
142→    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
143→    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
144→    totalSessions: totalRow.count,
145→    frictionTotal,
146→  };
147→}
148→
149→// Parse LLM JSON response wrapped in <json>...</json> tags with jsonrepair fallback.
150→function parseLLMJson<T>(response: string): T | null {
151→  const payload = extractJsonPayload(response);
152→  if (!payload) return null;
153→  try {
154→    return JSON.parse(payload) as T;
155→  } catch {
156→    try {
157→      return JSON.parse(jsonrepair(payload)) as T;
158→    } catch {
159→      return null;
160→    }
161→  }
162→}
163→
164→// Detect the dominant source tool from the database to target artifact generation.
165→function detectTargetTool(db: ReturnType<typeof getDb>): string {
166→  const row = db.prepare(
167→    `SELECT source_tool, COUNT(*) as count FROM sessions GROUP BY source_tool ORDER BY count DESC LIMIT 1`
168→  ).get() as { source_tool: string; count: number } | undefined;
169→  return row?.source_tool || 'claude-code';
170→}
