172→// POST /api/reflect/generate
173→// Body: { sections?: ReflectSection[], period?: string, project?: string, source?: string }
174→// SSE endpoint: aggregates facets in code, then calls synthesis prompts for each section.
175→// Streams progress events so the UI can show phase-by-phase progress.
176→app.post('/generate', async (c) => {
177→  if (!isLLMConfigured()) {
178→    return c.json({ error: 'LLM not configured.' }, 400);
179→  }
180→
181→  const body = await c.req.json<{
182→    sections?: ReflectSection[];
183→    period?: string;
184→    project?: string;
185→    source?: string;
186→  }>();
187→
188→  const sections = body.sections && body.sections.length > 0 ? body.sections : ALL_SECTIONS;
189→  const period = body.period || '7d';
190→
191→  const db = getDb();
192→  const { where, params } = buildWhereClause(period, body.project, body.source);
193→
194→  return streamSSE(c, async (stream) => {
195→    const abortSignal = c.req.raw.signal;
196→
197→    try {
198→      await stream.writeSSE({
199→        event: 'progress',
200→        data: JSON.stringify({ phase: 'aggregating', message: 'Aggregating facets...' }),
201→      });
202→
203→      const aggregated = getAggregatedData(db, where, params);
204→
205→      if (aggregated.totalSessions === 0) {
206→        await stream.writeSSE({
207→          event: 'error',
208→          data: JSON.stringify({ error: 'No sessions with facets found. Run analysis first.' }),
209→        });
210→        return;
211→      }
212→
213→      const client = createLLMClient();
214→      const results: Record<string, unknown> = {};
215→      const targetTool = detectTargetTool(db);
216→
217→      for (const section of sections) {
218→        if (abortSignal.aborted) break;
219→
220→        await stream.writeSSE({
221→          event: 'progress',
222→          data: JSON.stringify({ phase: 'synthesizing', section, message: `Generating ${section}...` }),
223→        });
224→
225→        if (section === 'friction-wins') {
226→          const prompt = generateFrictionWinsPrompt({
227→            frictionCategories: aggregated.frictionCategories,
228→            effectivePatterns: aggregated.effectivePatterns,
229→            totalSessions: aggregated.totalSessions,
230→            period,
231→          });
232→          const response = await client.chat([
233→            { role: 'system', content: FRICTION_WINS_SYSTEM_PROMPT },
234→            { role: 'user', content: prompt },
235→          ], { signal: abortSignal });
236→          const parsed = parseLLMJson(response.content);
237→          results['friction-wins'] = {
238→            section: 'friction-wins',
